  8→import { acquireContext, releaseContext } from "./browser-pool.js";
  9→import { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
 10→import { applyOpenAiStructuring } from "./openai-structuring.js";
 11→
 12→/* ── ChatGPT share-import constants ─────────────────────────── */
 13→
 14→/** Timeout for the initial page.goto() navigation. */
 15→export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 16→
 17→/** Timeout for waiting until message elements appear in the DOM. */
 18→export const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
 19→
 20→/** Extra delay after messages appear to let the page stabilize. */
 21→export const PAGE_STABILIZATION_MS = 800;
 22→
 23→/** CSS selector that identifies ChatGPT share-page message elements. */
 24→export const CHATGPT_SHARE_SELECTOR = "article [data-message-author-role]";
 25→
 26→/* ─────────────────────────────────────────────────────────── */
 27→
 28→type StageCallback = (
 29→  stage: Extract<ImportStage, "fetch" | "extract" | "normalize" | "structure">,
 30→) => void;
 31→
 32→type ImportResult = {
 33→  conversation: Conversation;
 34→  warnings: string[];
 35→  snapshot: {
 36→    finalUrl: string;
 37→    fetchedAt: string;
 38→    pageTitle: string;
 39→    rawHtml: string;
 40→    normalizedPayload: NormalizedSnapshotPayload;
 41→    fetchMetadata: {
 42→      articleCount: number;
 43→      messageCount: number;
 44→      rawHtmlBytes: number;
 45→    };
 46→  };
 47→};
 48→
 49→export async function importChatGptSharePage(
 50→  url: string,
 51→  options?: {
 52→    onStage?: StageCallback;
 53→  },
 54→): Promise<ImportResult> {
 55→  const context = await acquireContext();
 56→
 57→  try {
 58→    await context.route("**/*", (route) => {
 59→      const resourceType = route.request().resourceType();
 60→
 61→      if (
 62→        resourceType === "image" ||
 63→        resourceType === "media" ||
 64→        resourceType === "font"
 65→      ) {
 66→        return route.abort();
 67→      }
 68→
 69→      return route.continue();
 70→    });
 71→
 72→    const page = await context.newPage();
 73→    await page.addInitScript({
 74→      content: "globalThis.__name = (value) => value;",
 75→    });
 76→
 77→    options?.onStage?.("fetch");
 78→    await page.goto(url, {
 79→      waitUntil: "domcontentloaded",
 80→      timeout: PAGE_LOAD_TIMEOUT_MS,
 81→    });
 82→    await page.waitForFunction(
 83→      (selector) => document.querySelectorAll(selector).length > 0,
 84→      CHATGPT_SHARE_SELECTOR,
 85→      {
 86→        timeout: MESSAGE_WAIT_TIMEOUT_MS,
 87→      },
 88→    );
 89→    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 90→
 91→    options?.onStage?.("extract");
 92→    const extracted = await page.evaluate(() => {
 93→      const __name = <T>(value: T) => value;
 94→      const wrapperTags = new Set([
 95→        "ARTICLE",
 96→        "SECTION",
 97→        "DIV",
 98→        "SPAN",
 99→        "FIGURE",
100→        "MAIN",
101→      ]);
102→      const blockTags = new Set([
103→        "P",
104→        "H1",
105→        "H2",
106→        "H3",
107→        "H4",
108→        "H5",
109→        "H6",
110→        "UL",
111→        "OL",
112→        "PRE",
113→        "BLOCKQUOTE",
114→        "TABLE",
115→        "HR",
116→      ]);
117→      const codeLanguageLabels = new Set([
118→        "plain text",
119→        "text",
120→        "json",
121→        "javascript",
122→        "typescript",
123→        "ts",
124→        "js",
125→        "python",
126→        "bash",
127→        "shell",
128→        "sql",
129→        "html",
130→        "css",
131→        "markdown",
132→        "md",
133→        "yaml",
134→        "yml",
135→      ]);
136→
137→      function normalizeWhitespace(value: string) {
138→        return value
139→          .replace(/\u00a0/g, " ")
140→          .replace(/\r/g, "")
141→          .replace(/[ \t\f\v]+/g, " ")
142→          .replace(/ *\n */g, "\n")
143→          .replace(/\n{3,}/g, "\n\n")
144→          .trim();
145→      }
146→
147→      function inlineText(node: Node): string {
148→        if (node.nodeType === Node.TEXT_NODE) {
149→          return node.textContent ?? "";
150→        }
151→
152→        if (node.nodeType !== Node.ELEMENT_NODE) {
153→          return "";
154→        }
155→
156→        const element = node as HTMLElement;
157→        const tagName = element.tagName.toUpperCase();
158→
159→        if (
160→          tagName === "BUTTON" ||
161→          tagName === "SVG" ||
162→          tagName === "PATH" ||
163→          tagName === "USE" ||
164→          tagName === "IMG" ||
165→          tagName === "NOSCRIPT"
166→        ) {
167→          return "";
168→        }
169→
170→        if (tagName === "BR") {
171→          return "\n";
172→        }
173→
174→        const childText = Array.from(element.childNodes)
175→          .map(inlineText)
176→          .join("");
177→
178→        switch (tagName) {
179→          case "A": {
180→            const text = normalizeWhitespace(childText);
181→            const href = element.getAttribute("href");
182→            return href && text ? `[${text}](${href})` : text;
183→          }
184→          case "STRONG":
185→          case "B": {
186→            const text = normalizeWhitespace(childText);
187→            return text ? `**${text}**` : "";
188→          }
189→          case "EM":
190→          case "I": {
191→            const text = normalizeWhitespace(childText);
192→            return text ? `*${text}*` : "";
193→          }
194→          case "CODE": {
195→            if (element.closest("pre")) {
196→              return "";
197→            }
198→
199→            const text = normalizeWhitespace(childText);
200→            return text ? `\`${text}\`` : "";
201→          }
202→          case "DEL":
203→          case "S": {
204→            const text = normalizeWhitespace(childText);
205→            return text ? `~~${text}~~` : "";
206→          }
207→          default:
208→            return childText;
209→        }
210→      }
211→
212→      function inlineFromElement(element: Element) {
213→        return normalizeWhitespace(
214→          Array.from(element.childNodes).map(inlineText).join(""),
215→        );
216→      }
217→
218→      function extractListItems(listElement: Element, depth = 0): string[] {
219→        const items: string[] = [];
220→        const listItems = Array.from(listElement.children).filter(
221→          (child) => child.tagName === "LI",
222→        );
223→
224→        for (const listItem of listItems) {
225→          let ownText = "";
226→
227→          for (const childNode of Array.from(listItem.childNodes)) {
228→            if (
229→              childNode.nodeType === Node.ELEMENT_NODE &&
230→              ["UL", "OL"].includes((childNode as Element).tagName)
231→            ) {
232→              continue;
233→            }
234→
235→            ownText += inlineText(childNode);
236→          }
237→
238→          const normalized = normalizeWhitespace(ownText);
239→          if (normalized) {
240→            items.push(`${"  ".repeat(depth)}${normalized}`);
241→          }
242→
243→          const nestedLists = Array.from(listItem.children).filter((child) =>
244→            ["UL", "OL"].includes(child.tagName),
245→          );
246→
247→          for (const nestedList of nestedLists) {
248→            items.push(...extractListItems(nestedList, depth + 1));
249→          }
250→        }
251→
252→        return items;
253→      }
254→
255→      function detectCodeLanguage(preElement: HTMLElement) {
256→        const firstLine =
257→          preElement.innerText.split("\n")[0]?.trim().toLowerCase() ?? "";
258→
259→        if (codeLanguageLabels.has(firstLine)) {
260→          return firstLine === "plain text" ? "text" : firstLine;
261→        }
262→
263→        const classHint = Array.from(preElement.querySelectorAll("[class]"))
264→          .map((element) => element.className)
265→          .join(" ");
266→        const languageMatch = classHint.match(/language-([a-z0-9#+-]+)/i);
267→        return languageMatch?.[1]?.toLowerCase() ?? "text";
268→      }
269→
270→      function extractCodeText(preElement: HTMLElement) {
271→        const lines = preElement.innerText.replace(/\r/g, "").split("\n");
272→
273→        while (lines.length > 1) {
274→          const firstLine = lines[0]?.trim().toLowerCase() ?? "";
275→          if (
276→            !codeLanguageLabels.has(firstLine) &&
277→            firstLine !== "kopieren" &&
278→            firstLine !== "copy"
279→          ) {
280→            break;
281→          }
282→          lines.shift();
283→        }
284→
285→        return lines.join("\n").trim();
286→      }
287→
288→      function extractTable(tableElement: HTMLTableElement) {
289→        const headerRows = Array.from(
290→          tableElement.querySelectorAll("thead tr"),
291→        );
292→        const bodyRows = Array.from(tableElement.querySelectorAll("tbody tr"));
293→        const fallbackRows = Array.from(tableElement.querySelectorAll("tr"));
294→        const firstHeaderRow = headerRows[0];
295→
296→        const headers = firstHeaderRow
297→          ? Array.from(firstHeaderRow.querySelectorAll("th,td")).map((cell) =>
298→              inlineFromElement(cell),
299→            )
300→          : [];
301→
302→        const rowSource =
303→          bodyRows.length > 0
304→            ? bodyRows
305→            : fallbackRows.slice(headers.length > 0 ? 1 : 0);
306→        const rows = rowSource
307→          .map((row) =>
308→            Array.from(row.querySelectorAll("th,td")).map((cell) =>
309→              inlineFromElement(cell),
310→            ),
311→          )
312→          .filter((row) => row.some(Boolean));
313→
314→        if (headers.length === 0 && rows.length === 0) {
315→          return null;
316→        }
317→
318→        return {
319→          type: "table" as const,
320→          headers,
321→          rows,
322→        };
323→      }
324→
325→      function elementToBlocks(
326→        element: Element,
327→      ): Array<Record<string, unknown>> {
328→        const tagName = element.tagName.toUpperCase();
329→
330→        if (tagName === "P") {
331→          const text = inlineFromElement(element);
332→          return text ? [{ type: "paragraph", text }] : [];
333→        }
334→
335→        if (/^H[1-6]$/.test(tagName)) {
336→          const text = inlineFromElement(element);
337→          const level = Number(tagName.slice(1));
338→          return text ? [{ type: "heading", level, text }] : [];
339→        }
340→
341→        if (tagName === "UL" || tagName === "OL") {
342→          const items = extractListItems(element);
343→          return items.length > 0
344→            ? [
345→                {
346→                  type: "list",
347→                  ordered: tagName === "OL",
348→                  items,
349→                },
350→              ]
351→            : [];
352→        }
353→
354→        if (tagName === "PRE") {
355→          const text = extractCodeText(element as HTMLElement);
356→          return text
357→            ? [
358→                {
359→                  type: "code",
360→                  language: detectCodeLanguage(element as HTMLElement),
361→                  text,
362→                },
363→              ]
364→            : [];
365→        }
366→
367→        if (tagName === "BLOCKQUOTE") {
368→          const text = inlineFromElement(element);
369→          return text ? [{ type: "quote", text }] : [];
370→        }
371→
372→        if (tagName === "TABLE") {
373→          const table = extractTable(element as HTMLTableElement);
374→          return table ? [table] : [];
375→        }
376→
377→        if (tagName === "HR") {
378→          return [];
379→        }
380→
381→        if (wrapperTags.has(tagName)) {
382→          const childBlocks = Array.from(element.childNodes).flatMap(
383→            (childNode) => {
384→              if (childNode.nodeType === Node.TEXT_NODE) {
385→                const text = normalizeWhitespace(childNode.textContent ?? "");
386→                return text ? [{ type: "paragraph" as const, text }] : [];
387→              }
388→
389→              if (childNode.nodeType !== Node.ELEMENT_NODE) {
390→                return [];
391→              }
392→
393→              return elementToBlocks(childNode as Element);
394→            },
395→          );
396→
397→          if (childBlocks.length > 0) {
398→            return childBlocks;
399→          }
400→        }
401→
402→        const hasBlockChildren = Array.from(element.children).some((child) =>
403→          blockTags.has(child.tagName),
404→        );
405→
406→        if (hasBlockChildren) {
407→          return Array.from(element.children).flatMap((child) =>
408→            elementToBlocks(child),
409→          );
410→        }
411→
412→        const text = inlineFromElement(element);
413→        return text ? [{ type: "paragraph", text }] : [];
414→      }
415→
416→      function normalizeTitle(rawTitle: string) {
417→        const title = rawTitle.replace(/^ChatGPT\s*-\s*/i, "").trim();
418→        return title || "Untitled Chat";
419→      }
420→
421→      const warnings: string[] = [];
422→      const articles = Array.from(document.querySelectorAll("article"));
423→      let fallbackCount = 0;
424→
425→      const messages = articles
426→        .map((article) => {
427→          const messageElement = article.querySelector(
428→            "[data-message-author-role]",
429→          ) as HTMLElement | null;
430→          if (!messageElement) {
431→            return null;
432→          }
433→
434→          const role =
435→            messageElement.getAttribute("data-message-author-role") ??
436→            "unknown";
437→          const messageId =
438→            messageElement.getAttribute("data-message-id") ??
439→            crypto.randomUUID();
440→
441→          if (role === "assistant") {
442→            const markdownRoot =
443→              (messageElement.querySelector(
444→                ".markdown",
445→              ) as HTMLElement | null) ?? messageElement;
446→            const blocks = Array.from(markdownRoot.childNodes).flatMap(
447→              (childNode) => {
448→                if (childNode.nodeType === Node.TEXT_NODE) {
449→                  const text = normalizeWhitespace(childNode.textContent ?? "");
450→                  return text ? [{ type: "paragraph" as const, text }] : [];
451→                }
452→
453→                if (childNode.nodeType !== Node.ELEMENT_NODE) {
454→                  return [];
455→                }
456→
457→                return elementToBlocks(childNode as Element);
458→              },
459→            );
460→
461→            const rawText = normalizeWhitespace(messageElement.innerText);
462→            const rawHtml = messageElement.innerHTML;
463→
464→            if (blocks.length === 0) {
465→              fallbackCount += 1;
466→              return rawText
467→                ? {
468→                    id: messageId,
469→                    role,
470→                    rawText,
471→                    rawHtml,
472→                    blocks: [{ type: "paragraph" as const, text: rawText }],
473→                    parser: {
474→                      source: "assistant-fallback",
475→                      blockCount: 1,
476→                      usedFallback: true,
477→                      strategy: "fallback" as const,
478→                    },
479→                  }
480→                : null;
481→            }
482→
483→            return {
484→              id: messageId,
485→              role,
486→              rawText,
487→              rawHtml,
488→              blocks,
489→              parser: {
490→                source: "assistant-markdown",
491→                blockCount: blocks.length,
492→                usedFallback: false,
493→                strategy: "deterministic" as const,
494→              },
495→            };
496→          }
497→
498→          const textSource =
499→            (messageElement.querySelector(
500→              ".whitespace-pre-wrap",
501→            ) as HTMLElement | null) ?? messageElement;
502→          const text = normalizeWhitespace(textSource.innerText);
503→          const rawHtml = textSource.innerHTML;
504→
505→          return text
506→            ? {
507→                id: messageId,
508→                role,
509→                rawText: text,
510→                rawHtml,
511→                blocks: [{ type: "paragraph" as const, text }],
512→                parser: {
513→                  source:
514→                    textSource === messageElement
515→                      ? "user-message"
516→                      : "user-whitespace-pre-wrap",
517→                  blockCount: 1,
518→                  usedFallback: false,
519→                  strategy: "deterministic" as const,
520→                },
521→              }
522→            : null;
523→        })
524→        .filter(Boolean);
525→
526→      if (fallbackCount > 0) {
527→        warnings.push(
528→          `${fallbackCount} assistant message(s) fell back to a plain paragraph because no richer block structure was detected.`,
529→        );
530→      }
531→
532→      return {
533→        title: normalizeTitle(document.title),
534→        messages,
535→        warnings,
536→      };
537→    });
538→
539→    options?.onStage?.("normalize");
540→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
541→
542→    if (normalizedPayload.messages.length > MAX_MESSAGE_COUNT) {
543→      const originalCount = normalizedPayload.messages.length;
544→      normalizedPayload.messages = normalizedPayload.messages.slice(
545→        -MAX_MESSAGE_COUNT,
546→      );
547→      normalizedPayload.warnings.push(
548→        `Nachrichtenlimit überschritten: ${originalCount} Nachrichten gefunden, auf die letzten ${MAX_MESSAGE_COUNT} gekürzt.`,
549→      );
550→    }
551→
552→    options?.onStage?.("structure");
553→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
554→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
555→      ...normalizedPayload,
556→      messages: structured.messages,
557→      warnings: [...normalizedPayload.warnings, ...structured.warnings],
558→      structuring: structured.structuring,
559→    });
560→    const rawHtml = await page.content();
561→    const rawHtmlBytes = Buffer.byteLength(rawHtml, "utf8");
562→    if (rawHtmlBytes > MAX_RAW_HTML_BYTES) {
563→      const sizeMb = (rawHtmlBytes / (1024 * 1024)).toFixed(1);
564→      const limitMb = (MAX_RAW_HTML_BYTES / (1024 * 1024)).toFixed(1);
565→      throw new Error(
566→        `HTML-Größe überschritten: ${sizeMb} MB (Limit: ${limitMb} MB).`,
567→      );
568→    }
569→    const fetchedAt = new Date().toISOString();
570→
571→    const conversation = conversationSchema.parse({
572→      id: crypto.randomUUID(),
573→      title: finalPayload.title,
574→      source: {
575→        url,
576→        platform: "chatgpt",
577→      },
578→      messages: finalPayload.messages,
579→    });
580→
581→    return {
582→      conversation,
583→      warnings: finalPayload.warnings,
584→      snapshot: {
585→        finalUrl: page.url(),
586→        fetchedAt,
587→        pageTitle: finalPayload.title,
588→        rawHtml,
589→        normalizedPayload: finalPayload,
590→        fetchMetadata: {
591→          articleCount: normalizedPayload.messages.length,
592→          messageCount: conversation.messages.length,
593→          rawHtmlBytes: Buffer.byteLength(rawHtml, "utf8"),
594→        },
595→      },
596→    };
597→  } finally {
598→    await releaseContext(context);
599→  }
600→}
