  1→import type { Browser, BrowserContext } from "playwright";
  2→import { chromium } from "playwright";
  3→
  4→import {
  5→  BROWSER_IDLE_SHUTDOWN_MS,
  6→  MAX_CONCURRENT_BROWSER_CONTEXTS,
  7→} from "./constants.js";
  8→
  9→export const MAX_CONTEXTS_PER_BROWSER = 50;
 10→
 11→type QueueEntry = {
 12→  resolve: (ctx: BrowserContext) => void;
 13→  reject: (err: Error) => void;
 14→};
 15→
 16→let browser: Browser | null = null;
 17→let launchPromise: Promise<Browser> | null = null;
 18→let activeContextCount = 0;
 19→let totalContextCount = 0;
 20→let idleTimer: ReturnType<typeof setTimeout> | null = null;
 21→const queue: QueueEntry[] = [];
 22→
 23→function clearIdleTimer() {
 24→  if (idleTimer !== null) {
 25→    clearTimeout(idleTimer);
 26→    idleTimer = null;
 27→  }
 28→}
 29→
 30→function scheduleIdleShutdown() {
 31→  clearIdleTimer();
 32→  idleTimer = setTimeout(async () => {
 33→    if (activeContextCount === 0 && browser !== null) {
 34→      const instance = browser;
 35→      browser = null;
 36→      totalContextCount = 0;
 37→      await instance.close();
 38→    }
 39→  }, BROWSER_IDLE_SHUTDOWN_MS);
 40→}
 41→
 42→async function ensureBrowser(): Promise<Browser> {
 43→  if (browser !== null) {
 44→    return browser;
 45→  }
 46→
 47→  if (launchPromise !== null) {
 48→    return launchPromise;
 49→  }
 50→
 51→  launchPromise = (async () => {
 52→    const instance = await chromium.launch({ headless: true });
 53→    instance.on("disconnected", () => {
 54→      if (browser === instance) {
 55→        browser = null;
 56→        totalContextCount = 0;
 57→      }
 58→    });
 59→    browser = instance;
 60→    launchPromise = null;
 61→    return instance;
 62→  })();
 63→
 64→  return launchPromise;
 65→}
 66→
 67→async function createContext(): Promise<BrowserContext> {
 68→  if (
 69→    totalContextCount >= MAX_CONTEXTS_PER_BROWSER &&
 70→    activeContextCount === 0 &&
 71→    browser !== null
 72→  ) {
 73→    const old = browser;
 74→    browser = null;
 75→    totalContextCount = 0;
 76→    await old.close();
 77→  }
 78→
 79→  const instance = await ensureBrowser();
 80→  clearIdleTimer();
 81→
 82→  const ctx = await instance.newContext();
 83→  activeContextCount++;
 84→  totalContextCount++;
 85→  return ctx;
 86→}
 87→
 88→export async function acquireContext(): Promise<BrowserContext> {
 89→  if (activeContextCount >= MAX_CONCURRENT_BROWSER_CONTEXTS) {
 90→    return new Promise<BrowserContext>((resolve, reject) => {
 91→      queue.push({ resolve, reject });
 92→    });
 93→  }
 94→
 95→  return createContext();
 96→}
 97→
 98→export async function releaseContext(context: BrowserContext): Promise<void> {
 99→  await context.close();
100→  activeContextCount--;
101→
102→  if (queue.length > 0) {
103→    const next = queue.shift()!;
104→    try {
105→      const ctx = await createContext();
106→      next.resolve(ctx);
107→    } catch (err) {
108→      next.reject(err instanceof Error ? err : new Error(String(err)));
109→    }
110→  } else if (activeContextCount === 0) {
111→    scheduleIdleShutdown();
112→  }
113→}
114→
115→export async function shutdownPool(): Promise<void> {
116→  clearIdleTimer();
117→
118→  while (queue.length > 0) {
119→    const entry = queue.shift()!;
120→    entry.reject(new Error("Pool shut down"));
121→  }
122→
123→  if (browser !== null) {
124→    const instance = browser;
125→    browser = null;
126→    await instance.close();
127→  }
128→
129→  launchPromise = null;
130→  activeContextCount = 0;
131→  totalContextCount = 0;
132→}
133→
134→export function getPoolStats() {
135→  return {
136→    activeContexts: activeContextCount,
137→    queueLength: queue.length,
138→    browserConnected: browser !== null,
139→    totalContextsServed: totalContextCount,
140→  };
141→}
