 194→export async function importGenericSharePage(
 195→  url: string,
 196→  options: {
 197→    onStage?: StageCallback;
 198→    sourcePlatform: SourcePlatform;
 199→  },
 200→) {
 201→  const context = await acquireContext();
 202→
 203→  try {
 204→    if (!isGoogleSourcePlatform(options.sourcePlatform)) {
 205→      await context.route("**/*", (route) => {
 206→        const resourceType = route.request().resourceType();
 207→
 208→        if (
 209→          resourceType === "image" ||
 210→          resourceType === "media" ||
 211→          resourceType === "font"
 212→        ) {
 213→          return route.abort();
 214→        }
 215→
 216→        return route.continue();
 217→      });
 218→    }
 219→
 220→    const page = await context.newPage();
 221→    await page.addInitScript({
 222→      content: "globalThis.__name = (value) => value;",
 223→    });
 224→
 225→    const navigationTimeout = isGoogleSourcePlatform(options.sourcePlatform)
 226→      ? GOOGLE_NAVIGATION_TIMEOUT_MS
 227→      : DEFAULT_NAVIGATION_TIMEOUT_MS;
 228→
 229→    options.onStage?.("fetch");
 230→    await page.goto(url, {
 231→      waitUntil: "commit",
 232→      timeout: navigationTimeout,
 233→    });
 234→    await page
 235→      .waitForLoadState("domcontentloaded", {
 236→        timeout: DOM_CONTENT_LOADED_TIMEOUT_MS,
 237→      })
 238→      .catch(() => undefined);
 239→
 240→    if (isGoogleSourcePlatform(options.sourcePlatform)) {
 241→      await maybeDismissGoogleConsentGate(page);
 242→    }
 243→
 244→    if (isGoogleConsentUrl(page.url())) {
 245→      throw new Error(
 246→        `Google showed a cookie consent gate instead of the ${options.sourcePlatform} share page.`,
 247→      );
 248→    }
 249→
 250→    await page
 251→      .waitForFunction(
 252→        () => {
 253→          const root =
 254→            document.querySelector("main, [role='main'], article, body") ??
 255→            document.body;
 256→          return (root.textContent ?? "").trim().length > 32;
 257→        },
 258→        {
 259→          timeout: FUNCTION_WAIT_TIMEOUT_MS,
 260→        },
 261→      )
 262→      .catch(() => undefined);
