 264→    await page
 265→      .waitForLoadState("networkidle", {
 266→        timeout: NETWORK_IDLE_TIMEOUT_MS,
 267→      })
 268→      .catch(() => undefined);
 269→    await page.waitForTimeout(PAGE_STABILIZATION_DELAY_MS);
 270→
 271→    options.onStage?.("extract");
 272→    const extractionConfig = {
 273→      MIN_CONTENT_TEXT_LENGTH,
 274→      MIN_MEANINGFUL_CHILDREN,
 275→      MIN_CHILD_TEXT_LENGTH,
 276→      MIN_TEXT_LENGTH_FOR_MEANINGFUL_CHILDREN,
 277→      MAX_SAMPLE_CHILDREN,
 278→      MAX_TEXT_LENGTH_FOR_AVERAGING,
 279→      MAX_CONTAINER_CANDIDATES,
 280→      SCORE_CHILDREN_WEIGHT,
 281→      SCORE_TAG_RATIO_WEIGHT,
 282→      SCORE_HINTED_WEIGHT,
 283→      SCORE_BLOCK_WEIGHT,
 284→      SCORE_ACTION_WEIGHT,
 285→      SCORE_AVG_TEXT_DIVISOR,
 286→      SCORE_AVG_TEXT_MAX,
 287→      SCORE_DEPTH_PENALTY,
 288→      SCORE_FORM_PENALTY,
 289→      CANDIDATE_DEDUP_THRESHOLD,
 290→      MIN_CONTAINER_SCORE_THRESHOLD,
 291→      MIN_FALLBACK_TEXT_LENGTH,
 292→      MAX_FALLBACK_TEXT_LENGTH,
 293→      MAX_FALLBACK_CANDIDATES,
 294→      MAX_HINT_DEPTH,
 295→      MAX_HINT_CLASSES,
 296→    };
 297→    const extracted = await page.evaluate(
 298→      ({ platform, cfg }) => {
 299→        const wrapperTags = new Set([
 300→          "ARTICLE",
 301→          "SECTION",
 302→          "DIV",
 303→          "SPAN",
 304→          "FIGURE",
 305→          "MAIN",
 306→        ]);
 307→        const blockTags = new Set([
 308→          "P",
 309→          "H1",
 310→          "H2",
 311→          "H3",
 312→          "H4",
 313→          "H5",
 314→          "H6",
 315→          "UL",
 316→          "OL",
 317→          "PRE",
 318→          "BLOCKQUOTE",
 319→          "TABLE",
 320→          "HR",
 321→        ]);
 322→        const codeLanguageLabels = new Set([
 323→          "plain text",
 324→          "text",
 325→          "json",
 326→          "javascript",
 327→          "typescript",
 328→          "ts",
 329→          "js",
 330→          "python",
 331→          "bash",
 332→          "shell",
 333→          "sql",
 334→          "html",
 335→          "css",
 336→          "markdown",
 337→          "md",
 338→          "yaml",
 339→          "yml",
 340→        ]);
 341→
 342→        function normalizeWhitespace(value: string | null | undefined) {
 343→          return (value ?? "")
 344→            .replace(/\u00a0/g, " ")
 345→            .replace(/\r/g, "")
 346→            .replace(/[ \t\f\v]+/g, " ")
 347→            .replace(/ *\n */g, "\n")
 348→            .replace(/\n{3,}/g, "\n\n")
 349→            .trim();
 350→        }
 351→
 352→        function inlineText(node: Node): string {
 353→          if (node.nodeType === Node.TEXT_NODE) {
 354→            return node.textContent ?? "";
 355→          }
 356→
 357→          if (node.nodeType !== Node.ELEMENT_NODE) {
 358→            return "";
 359→          }
 360→
 361→          const element = node as HTMLElement;
 362→          const tagName = element.tagName.toUpperCase();
 363→
 364→          if (
 365→            tagName === "BUTTON" ||
 366→            tagName === "SVG" ||
 367→            tagName === "PATH" ||
 368→            tagName === "USE" ||
 369→            tagName === "IMG" ||
 370→            tagName === "NOSCRIPT"
 371→          ) {
 372→            return "";
 373→          }
 374→
 375→          if (tagName === "BR") {
 376→            return "\n";
 377→          }
 378→
 379→          const childText = Array.from(element.childNodes)
 380→            .map(inlineText)
 381→            .join("");
 382→
 383→          switch (tagName) {
 384→            case "A": {
 385→              const text = normalizeWhitespace(childText);
 386→              const href = element.getAttribute("href");
 387→              return href && text ? `[${text}](${href})` : text;
 388→            }
 389→            case "STRONG":
 390→            case "B": {
 391→              const text = normalizeWhitespace(childText);
 392→              return text ? `**${text}**` : "";
 393→            }
 394→            case "EM":
 395→            case "I": {
 396→              const text = normalizeWhitespace(childText);
 397→              return text ? `*${text}*` : "";
 398→            }
 399→            case "CODE": {
 400→              if (element.closest("pre")) {
 401→                return "";
 402→              }
 403→
 404→              const text = normalizeWhitespace(childText);
 405→              return text ? `\`${text}\`` : "";
 406→            }
 407→            case "DEL":
 408→            case "S": {
 409→              const text = normalizeWhitespace(childText);
 410→              return text ? `~~${text}~~` : "";
 411→            }
 412→            default:
 413→              return childText;
 414→          }
 415→        }
 416→
 417→        function inlineFromElement(element: Element) {
 418→          return normalizeWhitespace(
 419→            Array.from(element.childNodes).map(inlineText).join(""),
 420→          );
 421→        }
 422→
 423→        function extractListItems(listElement: Element, depth = 0): string[] {
 424→          const items: string[] = [];
 425→          const listItems = Array.from(listElement.children).filter(
 426→            (child) => child.tagName === "LI",
 427→          );
 428→
 429→          for (const listItem of listItems) {
 430→            let ownText = "";
 431→
 432→            for (const childNode of Array.from(listItem.childNodes)) {
 433→              if (
 434→                childNode.nodeType === Node.ELEMENT_NODE &&
 435→                ["UL", "OL"].includes((childNode as Element).tagName)
 436→              ) {
 437→                continue;
 438→              }
 439→
 440→              ownText += inlineText(childNode);
 441→            }
 442→
 443→            const normalized = normalizeWhitespace(ownText);
 444→            if (normalized) {
 445→              items.push(`${"  ".repeat(depth)}${normalized}`);
 446→            }
 447→
 448→            const nestedLists = Array.from(listItem.children).filter((child) =>
 449→              ["UL", "OL"].includes(child.tagName),
 450→            );
 451→
 452→            for (const nestedList of nestedLists) {
 453→              items.push(...extractListItems(nestedList, depth + 1));
 454→            }
 455→          }
 456→
 457→          return items;
 458→        }
 459→
 460→        function detectCodeLanguage(preElement: HTMLElement) {
 461→          const firstLine =
 462→            preElement.innerText.split("\n")[0]?.trim().toLowerCase() ?? "";
 463→
 464→          if (codeLanguageLabels.has(firstLine)) {
 465→            return firstLine === "plain text" ? "text" : firstLine;
 466→          }
 467→
 468→          const classHint = Array.from(preElement.querySelectorAll("[class]"))
 469→            .map((element) => element.className)
 470→            .join(" ");
 471→          const languageMatch = classHint.match(/language-([a-z0-9#+-]+)/i);
 472→          return languageMatch?.[1]?.toLowerCase() ?? "text";
 473→        }
 474→
 475→        function extractCodeText(preElement: HTMLElement) {
 476→          const lines = preElement.innerText.replace(/\r/g, "").split("\n");
 477→
 478→          while (lines.length > 1) {
 479→            const firstLine = lines[0]?.trim().toLowerCase() ?? "";
 480→            if (
 481→              !codeLanguageLabels.has(firstLine) &&
 482→              firstLine !== "kopieren" &&
 483→              firstLine !== "copy"
 484→            ) {
 485→              break;
 486→            }
 487→            lines.shift();
 488→          }
 489→
 490→          return lines.join("\n").trim();
 491→        }
 492→
 493→        function extractTable(tableElement: HTMLTableElement) {
 494→          const headerRows = Array.from(
 495→            tableElement.querySelectorAll("thead tr"),
 496→          );
 497→          const bodyRows = Array.from(
 498→            tableElement.querySelectorAll("tbody tr"),
 499→          );
 500→          const fallbackRows = Array.from(tableElement.querySelectorAll("tr"));
 501→          const firstHeaderRow = headerRows[0];
 502→
 503→          const headers = firstHeaderRow
 504→            ? Array.from(firstHeaderRow.querySelectorAll("th,td")).map((cell) =>
 505→                inlineFromElement(cell),
 506→              )
 507→            : [];
 508→
 509→          const rowSource =
 510→            bodyRows.length > 0
 511→              ? bodyRows
 512→              : fallbackRows.slice(headers.length > 0 ? 1 : 0);
 513→          const rows = rowSource
 514→            .map((row) =>
 515→              Array.from(row.querySelectorAll("th,td")).map((cell) =>
 516→                inlineFromElement(cell),
 517→              ),
 518→            )
 519→            .filter((row) => row.some(Boolean));
 520→
 521→          if (headers.length === 0 && rows.length === 0) {
 522→            return null;
 523→          }
 524→
 525→          return {
 526→            type: "table" as const,
 527→            headers,
 528→            rows,
 529→          };
 530→        }
 531→
 532→        function elementToBlocks(
 533→          element: Element,
 534→        ): Array<Record<string, unknown>> {
 535→          const tagName = element.tagName.toUpperCase();
 536→
 537→          if (tagName === "P") {
 538→            const text = inlineFromElement(element);
 539→            return text ? [{ type: "paragraph", text }] : [];
 540→          }
 541→
 542→          if (/^H[1-6]$/.test(tagName)) {
 543→            const text = inlineFromElement(element);
 544→            const level = Number(tagName.slice(1));
 545→            return text ? [{ type: "heading", level, text }] : [];
 546→          }
 547→
 548→          if (tagName === "UL" || tagName === "OL") {
 549→            const items = extractListItems(element);
 550→            return items.length > 0
 551→              ? [
 552→                  {
 553→                    type: "list",
 554→                    ordered: tagName === "OL",
 555→                    items,
 556→                  },
 557→                ]
 558→              : [];
 559→          }
 560→
 561→          if (tagName === "PRE") {
 562→            const text = extractCodeText(element as HTMLElement);
 563→            return text
 564→              ? [
 565→                  {
 566→                    type: "code",
 567→                    language: detectCodeLanguage(element as HTMLElement),
 568→                    text,
 569→                  },
 570→                ]
 571→              : [];
 572→          }
 573→
 574→          if (tagName === "BLOCKQUOTE") {
 575→            const text = inlineFromElement(element);
 576→            return text ? [{ type: "quote", text }] : [];
 577→          }
 578→
 579→          if (tagName === "TABLE") {
 580→            const table = extractTable(element as HTMLTableElement);
 581→            return table ? [table] : [];
 582→          }
 583→
 584→          if (tagName === "HR") {
 585→            return [];
 586→          }
 587→
 588→          if (wrapperTags.has(tagName)) {
 589→            const childBlocks = Array.from(element.childNodes).flatMap(
 590→              (childNode) => {
 591→                if (childNode.nodeType === Node.TEXT_NODE) {
 592→                  const text = normalizeWhitespace(childNode.textContent ?? "");
 593→                  return text ? [{ type: "paragraph" as const, text }] : [];
 594→                }
 595→
 596→                if (childNode.nodeType !== Node.ELEMENT_NODE) {
 597→                  return [];
 598→                }
 599→
 600→                return elementToBlocks(childNode as Element);
 601→              },
 602→            );
 603→
 604→            if (childBlocks.length > 0) {
 605→              return childBlocks;
 606→            }
 607→          }
 608→
 609→          const hasBlockChildren = Array.from(element.children).some((child) =>
 610→            blockTags.has(child.tagName),
 611→          );
 612→
 613→          if (hasBlockChildren) {
 614→            return Array.from(element.children).flatMap((child) =>
 615→              elementToBlocks(child),
 616→            );
 617→          }
 618→
 619→          const text = inlineFromElement(element);
 620→          return text ? [{ type: "paragraph", text }] : [];
 621→        }
 622→
 623→        function normalizeTitle(rawTitle: string) {
 624→          const title = rawTitle
 625→            .replace(/\|\s*shared .*$/i, "")
 626→            .replace(
 627→              /^(chatgpt|claude|gemini|grok|deepseek|notebooklm)\s*[-|:]\s*/i,
 628→              "",
 629→            )
 630→            .replace(/^shared\s+/i, "")
 631→            .trim();
 632→
 633→          return title || "Untitled Chat";
 634→        }
 635→
 636→        function pickExtractionRoot() {
 637→          const candidates = [
 638→            document.querySelector("main"),
 639→            document.querySelector("[role='main']"),
 640→            document.querySelector("article"),
 641→            document.body,
 642→          ].filter(Boolean) as Element[];
 643→
 644→          return (
 645→            candidates.find(
 646→              (candidate) =>
 647→                normalizeWhitespace((candidate as HTMLElement).innerText)
 648→                  .length > cfg.MIN_CONTENT_TEXT_LENGTH,
 649→            ) ?? document.body
 650→          );
 651→        }
 652→
 653→        function isExcluded(element: Element) {
 654→          return Boolean(
 655→            element.closest(
 656→              "nav,header,footer,aside,form,dialog,[role='navigation'],[aria-hidden='true']",
 657→            ),
 658→          );
 659→        }
 660→
 661→        function isVisible(element: Element) {
 662→          const computed = globalThis.getComputedStyle(element as HTMLElement);
 663→
 664→          if (
 665→            computed.display === "none" ||
 666→            computed.visibility === "hidden" ||
 667→            computed.opacity === "0"
 668→          ) {
 669→            return false;
 670→          }
 671→
 672→          const rect = (element as HTMLElement).getBoundingClientRect();
 673→          return rect.width > 0 && rect.height > 0;
 674→        }
 675→
 676→        function textContentLength(element: Element) {
 677→          return normalizeWhitespace((element as HTMLElement).innerText).length;
 678→        }
 679→
 680→        function blockDescendantCount(element: Element) {
 681→          return element.querySelectorAll(
 682→            "p,h1,h2,h3,h4,h5,h6,ul,ol,pre,blockquote,table",
 683→          ).length;
 684→        }
 685→
 686→        function attributeHintText(element: Element) {
 687→          const node = element as HTMLElement;
 688→          return [
 689→            element.getAttribute("data-message-author-role") ?? "",
 690→            element.getAttribute("data-author-role") ?? "",
 691→            element.getAttribute("data-role") ?? "",
 692→            element.getAttribute("data-testid") ?? "",
 693→            element.getAttribute("aria-label") ?? "",
 694→            node.id ?? "",
 695→            typeof node.className === "string" ? node.className : "",
 696→          ]
 697→            .join(" ")
 698→            .toLowerCase();
 699→        }
 700→
 701→        function hasConversationHints(element: Element) {
 702→          return /(message|conversation|turn|chat|prompt|response|assistant|user|claude|gemini|grok|deepseek|notebooklm)/i.test(
 703→            attributeHintText(element),
 704→          );
 705→        }
 706→
 707→        function elementDepth(element: Element) {
 708→          let depth = 0;
 709→          let current = element.parentElement;
 710→
 711→          while (current) {
 712→            depth += 1;
 713→            current = current.parentElement;
 714→          }
 715→
 716→          return depth;
 717→        }
 718→
 719→        function meaningfulDirectChildren(element: Element) {
 720→          return Array.from(element.children).filter((child) => {
 721→            if (!isVisible(child) || isExcluded(child)) {
 722→              return false;
 723→            }
 724→
 725→            if (child.querySelector("nav,header,footer,aside,form,dialog")) {
 726→              return false;
 727→            }
 728→
 729→            const textLength = textContentLength(child);
 730→            if (textLength < cfg.MIN_CHILD_TEXT_LENGTH) {
 731→              return false;
 732→            }
 733→
 734→            const blockCount = blockDescendantCount(child);
 735→            const buttonCount = child.querySelectorAll("button").length;
 736→
 737→            return (
 738→              blockCount > 0 ||
 739→              textLength > cfg.MIN_TEXT_LENGTH_FOR_MEANINGFUL_CHILDREN ||
 740→              buttonCount > 0
 741→            );
 742→          });
 743→        }
 744→
 745→        function scoreContainer(element: Element) {
 746→          const children = meaningfulDirectChildren(element);
 747→
 748→          if (children.length < cfg.MIN_MEANINGFUL_CHILDREN) {
 749→            return {
 750→              score: Number.NEGATIVE_INFINITY,
 751→              children,
 752→            };
 753→          }
 754→
 755→          const sampleChildren = children.slice(0, cfg.MAX_SAMPLE_CHILDREN);
 756→          const avgTextLength =
 757→            sampleChildren.reduce(
 758→              (sum, child) =>
 759→                sum +
 760→                Math.min(
 761→                  textContentLength(child),
 762→                  cfg.MAX_TEXT_LENGTH_FOR_AVERAGING,
 763→                ),
 764→              0,
 765→            ) / sampleChildren.length;
 766→          const blockHeavyCount = sampleChildren.filter(
 767→            (child) => blockDescendantCount(child) > 0,
 768→          ).length;
 769→          const hintedCount =
 770→            sampleChildren.filter(hasConversationHints).length;
 771→          const actionBarCount = sampleChildren.filter(
 772→            (child) => child.querySelectorAll("button").length > 0,
 773→          ).length;
 774→          const tagCounts = new Map<string, number>();
 775→
 776→          for (const child of sampleChildren) {
 777→            tagCounts.set(
 778→              child.tagName,
 779→              (tagCounts.get(child.tagName) ?? 0) + 1,
 780→            );
 781→          }
 782→
 783→          const repeatedTagRatio =
 784→            sampleChildren.length > 0
 785→              ? Math.max(...Array.from(tagCounts.values())) /
 786→                sampleChildren.length
 787→              : 0;
 788→
 789→          const formPenalty = element.querySelectorAll(
 790→            "input,textarea,select",
 791→          ).length;
 792→
 793→          return {
 794→            score:
 795→              sampleChildren.length * cfg.SCORE_CHILDREN_WEIGHT +
 796→              repeatedTagRatio * cfg.SCORE_TAG_RATIO_WEIGHT +
 797→              hintedCount * cfg.SCORE_HINTED_WEIGHT +
 798→              blockHeavyCount * cfg.SCORE_BLOCK_WEIGHT +
 799→              actionBarCount * cfg.SCORE_ACTION_WEIGHT +
 800→              Math.min(
 801→                avgTextLength / cfg.SCORE_AVG_TEXT_DIVISOR,
 802→                cfg.SCORE_AVG_TEXT_MAX,
 803→              ) -
 804→              elementDepth(element) * cfg.SCORE_DEPTH_PENALTY -
 805→              formPenalty * cfg.SCORE_FORM_PENALTY,
 806→            children,
 807→          };
 808→        }
 809→
 810→        function dedupeCandidates(
 811→          elements: Element[],
 812→          maxRootTextLength: number,
 813→        ) {
 814→          const sorted = Array.from(new Set(elements)).sort(
 815→            (left, right) => elementDepth(right) - elementDepth(left),
 816→          );
 817→          const unique: Element[] = [];
 818→          const seenText = new Set<string>();
 819→
 820→          for (const element of sorted) {
 821→            if (!isVisible(element) || isExcluded(element)) {
 822→              continue;
 823→            }
 824→
 825→            const text = normalizeWhitespace(
 826→              (element as HTMLElement).innerText,
 827→            );
 828→            if (!text) {
 829→              continue;
 830→            }
 831→
 832→            if (
 833→              text.length >=
 834→              maxRootTextLength * cfg.CANDIDATE_DEDUP_THRESHOLD
 835→            ) {
 836→              continue;
 837→            }
 838→
 839→            if (seenText.has(text)) {
 840→              continue;
 841→            }
 842→
 843→            if (
