  1→/**
  2→ * Browser-injectable script that defines shared DOM parsing helpers on globalThis.__domKit.
  3→ *
  4→ * Usage in parser files:
  5→ *   await page.addInitScript({ content: DOM_KIT_SCRIPT });
  6→ *   const result = await page.evaluate(() => {
  7→ *     const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
  8→ *     // ... use helpers ...
  9→ *   });
 10→ */
 11→export const DOM_KIT_SCRIPT: string = `(function() {
 12→  var wrapperTags = new Set(["ARTICLE", "SECTION", "DIV", "SPAN", "FIGURE", "MAIN"]);
 13→  var blockTags = new Set(["P", "H1", "H2", "H3", "H4", "H5", "H6", "UL", "OL", "PRE", "BLOCKQUOTE", "TABLE", "HR"]);
 14→  var codeLanguageLabels = new Set(["plain text", "text", "json", "javascript", "typescript", "ts", "js", "python", "bash", "shell", "sql", "html", "css", "markdown", "md", "yaml", "yml"]);
 15→
 16→  function normalizeWhitespace(value) {
 17→    return (value != null ? value : "")
 18→      .replace(/\\u00a0/g, " ")
 19→      .replace(/\\r/g, "")
 20→      .replace(/[ \\t\\f\\v]+/g, " ")
 21→      .replace(/ *\\n */g, "\\n")
 22→      .replace(/\\n{3,}/g, "\\n\\n")
 23→      .trim();
 24→  }
 25→
 26→  function inlineText(node) {
 27→    if (node.nodeType === Node.TEXT_NODE) {
 28→      return node.textContent != null ? node.textContent : "";
 29→    }
 30→
 31→    if (node.nodeType !== Node.ELEMENT_NODE) {
 32→      return "";
 33→    }
 34→
 35→    var element = node;
 36→    var tagName = element.tagName.toUpperCase();
 37→
 38→    if (
 39→      tagName === "BUTTON" ||
 40→      tagName === "SVG" ||
 41→      tagName === "PATH" ||
 42→      tagName === "USE" ||
 43→      tagName === "IMG" ||
 44→      tagName === "NOSCRIPT"
 45→    ) {
 46→      return "";
 47→    }
 48→
 49→    if (tagName === "BR") {
 50→      return "\\n";
 51→    }
 52→
 53→    var childText = Array.from(element.childNodes)
 54→      .map(inlineText)
 55→      .join("");
 56→
 57→    switch (tagName) {
 58→      case "A": {
 59→        var text = normalizeWhitespace(childText);
 60→        var href = element.getAttribute("href");
 61→        return href && text ? "[" + text + "](" + href + ")" : text;
 62→      }
 63→      case "STRONG":
 64→      case "B": {
 65→        var text = normalizeWhitespace(childText);
 66→        return text ? "**" + text + "**" : "";
 67→      }
 68→      case "EM":
 69→      case "I": {
 70→        var text = normalizeWhitespace(childText);
 71→        return text ? "*" + text + "*" : "";
 72→      }
 73→      case "CODE": {
 74→        if (element.closest("pre")) {
 75→          return "";
 76→        }
 77→        var text = normalizeWhitespace(childText);
 78→        return text ? "\`" + text + "\`" : "";
 79→      }
 80→      case "DEL":
 81→      case "S": {
 82→        var text = normalizeWhitespace(childText);
 83→        return text ? "~~" + text + "~~" : "";
 84→      }
 85→      default:
 86→        return childText;
 87→    }
 88→  }
 89→
 90→  function inlineFromElement(element) {
 91→    return normalizeWhitespace(
 92→      Array.from(element.childNodes).map(inlineText).join("")
 93→    );
 94→  }
 95→
 96→  function extractListItems(listElement, depth) {
 97→    if (depth === undefined) depth = 0;
 98→    var items = [];
 99→    var listItems = Array.from(listElement.children).filter(
100→      function(child) { return child.tagName === "LI"; }
101→    );
102→
103→    for (var i = 0; i < listItems.length; i++) {
104→      var listItem = listItems[i];
105→      var ownText = "";
106→
107→      var childNodes = Array.from(listItem.childNodes);
108→      for (var j = 0; j < childNodes.length; j++) {
109→        var childNode = childNodes[j];
110→        if (
111→          childNode.nodeType === Node.ELEMENT_NODE &&
112→          (childNode.tagName === "UL" || childNode.tagName === "OL")
113→        ) {
114→          continue;
115→        }
116→        ownText += inlineText(childNode);
117→      }
118→
119→      var normalized = normalizeWhitespace(ownText);
120→      if (normalized) {
121→        var indent = "";
122→        for (var d = 0; d < depth; d++) indent += "  ";
123→        items.push(indent + normalized);
124→      }
125→
126→      var nestedLists = Array.from(listItem.children).filter(function(child) {
127→        return child.tagName === "UL" || child.tagName === "OL";
128→      });
129→
130→      for (var k = 0; k < nestedLists.length; k++) {
131→        var nested = extractListItems(nestedLists[k], depth + 1);
132→        for (var m = 0; m < nested.length; m++) {
133→          items.push(nested[m]);
134→        }
135→      }
136→    }
137→
138→    return items;
139→  }
140→
141→  function detectCodeLanguage(preElement) {
142→    var firstLine = (preElement.innerText.split("\\n")[0] || "").trim().toLowerCase();
143→
144→    if (codeLanguageLabels.has(firstLine)) {
145→      return firstLine === "plain text" ? "text" : firstLine;
146→    }
147→
148→    var classHint = Array.from(preElement.querySelectorAll("[class]"))
149→      .map(function(el) { return el.className; })
150→      .join(" ");
151→    var languageMatch = classHint.match(/language-([a-z0-9#+-]+)/i);
152→    return languageMatch && languageMatch[1] ? languageMatch[1].toLowerCase() : "text";
153→  }
154→
155→  function extractCodeText(preElement) {
156→    var lines = preElement.innerText.replace(/\\r/g, "").split("\\n");
157→
158→    while (lines.length > 1) {
159→      var firstLine = (lines[0] || "").trim().toLowerCase();
160→      if (
161→        !codeLanguageLabels.has(firstLine) &&
162→        firstLine !== "kopieren" &&
163→        firstLine !== "copy"
164→      ) {
165→        break;
166→      }
167→      lines.shift();
168→    }
169→
170→    return lines.join("\\n").trim();
171→  }
172→
173→  function extractTable(tableElement) {
174→    var headerRows = Array.from(tableElement.querySelectorAll("thead tr"));
175→    var bodyRows = Array.from(tableElement.querySelectorAll("tbody tr"));
176→    var fallbackRows = Array.from(tableElement.querySelectorAll("tr"));
177→    var firstHeaderRow = headerRows[0];
178→
179→    var headers = firstHeaderRow
180→      ? Array.from(firstHeaderRow.querySelectorAll("th,td")).map(function(cell) {
181→          return inlineFromElement(cell);
182→        })
183→      : [];
184→
185→    var rowSource =
186→      bodyRows.length > 0
187→        ? bodyRows
188→        : fallbackRows.slice(headers.length > 0 ? 1 : 0);
189→    var rows = rowSource
190→      .map(function(row) {
191→        return Array.from(row.querySelectorAll("th,td")).map(function(cell) {
192→          return inlineFromElement(cell);
193→        });
194→      })
195→      .filter(function(row) { return row.some(Boolean); });
196→
197→    if (headers.length === 0 && rows.length === 0) {
198→      return null;
199→    }
200→
201→    return {
202→      type: "table",
203→      headers: headers,
204→      rows: rows
205→    };
206→  }
207→
208→  function elementToBlocks(element) {
209→    var tagName = element.tagName.toUpperCase();
210→
211→    if (tagName === "P") {
212→      var text = inlineFromElement(element);
213→      return text ? [{ type: "paragraph", text: text }] : [];
214→    }
215→
216→    if (/^H[1-6]$/.test(tagName)) {
217→      var text = inlineFromElement(element);
218→      var level = Number(tagName.slice(1));
219→      return text ? [{ type: "heading", level: level, text: text }] : [];
220→    }
221→
222→    if (tagName === "UL" || tagName === "OL") {
223→      var items = extractListItems(element);
224→      return items.length > 0
225→        ? [{ type: "list", ordered: tagName === "OL", items: items }]
226→        : [];
227→    }
228→
229→    if (tagName === "PRE") {
230→      var text = extractCodeText(element);
231→      return text
232→        ? [{ type: "code", language: detectCodeLanguage(element), text: text }]
233→        : [];
234→    }
235→
236→    if (tagName === "BLOCKQUOTE") {
237→      var text = inlineFromElement(element);
238→      return text ? [{ type: "quote", text: text }] : [];
239→    }
240→
241→    if (tagName === "TABLE") {
242→      var table = extractTable(element);
243→      return table ? [table] : [];
244→    }
245→
246→    if (tagName === "HR") {
247→      return [];
248→    }
249→
250→    if (wrapperTags.has(tagName)) {
251→      var childBlocks = Array.from(element.childNodes).reduce(function(acc, childNode) {
252→        if (childNode.nodeType === Node.TEXT_NODE) {
253→          var text = normalizeWhitespace(childNode.textContent != null ? childNode.textContent : "");
254→          if (text) acc.push({ type: "paragraph", text: text });
255→          return acc;
256→        }
257→
258→        if (childNode.nodeType !== Node.ELEMENT_NODE) {
259→          return acc;
260→        }
261→
262→        var blocks = elementToBlocks(childNode);
263→        for (var b = 0; b < blocks.length; b++) acc.push(blocks[b]);
264→        return acc;
265→      }, []);
266→
267→      if (childBlocks.length > 0) {
268→        return childBlocks;
269→      }
270→    }
271→
272→    var hasBlockChildren = Array.from(element.children).some(function(child) {
273→      return blockTags.has(child.tagName);
274→    });
275→
276→    if (hasBlockChildren) {
277→      return Array.from(element.children).reduce(function(acc, child) {
278→        var blocks = elementToBlocks(child);
279→        for (var b = 0; b < blocks.length; b++) acc.push(blocks[b]);
280→        return acc;
281→      }, []);
282→    }
283→
284→    var text = inlineFromElement(element);
285→    return text ? [{ type: "paragraph", text: text }] : [];
286→  }
287→
288→  globalThis.__domKit = {
289→    wrapperTags: wrapperTags,
290→    blockTags: blockTags,
291→    codeLanguageLabels: codeLanguageLabels,
292→    normalizeWhitespace: normalizeWhitespace,
293→    inlineText: inlineText,
294→    inlineFromElement: inlineFromElement,
295→    extractListItems: extractListItems,
296→    detectCodeLanguage: detectCodeLanguage,
297→    extractCodeText: extractCodeText,
298→    extractTable: extractTable,
299→    elementToBlocks: elementToBlocks
300→  };
301→})();`;
302→
303→/** TypeScript interface describing what __domKit provides in browser context. */
304→export interface DomKit {
305→  wrapperTags: Set<string>;
306→  blockTags: Set<string>;
307→  codeLanguageLabels: Set<string>;
308→  normalizeWhitespace: (value: string | null | undefined) => string;
309→  inlineText: (node: Node) => string;
310→  inlineFromElement: (element: Element) => string;
311→  extractListItems: (listElement: Element, depth?: number) => string[];
312→  detectCodeLanguage: (preElement: HTMLElement) => string;
313→  extractCodeText: (preElement: HTMLElement) => string;
314→  extractTable: (
315→    tableElement: HTMLTableElement,
316→  ) => { type: "table"; headers: string[]; rows: string[][] } | null;
317→  elementToBlocks: (element: Element) => Array<Record<string, unknown>>;
318→}
319→
320→// Augment globalThis for browser context
321→declare global {
322→  var __domKit: DomKit;
323→}
324→

