## Task: Plan Step 0.6 — Add Parser Registry/Dispatcher Pattern to share-import.ts

Convert `share-import.ts` from hardcoded if/else to a flexible parser registry pattern that new parsers can register with.

### Current Code

File: `apps/server/src/lib/share-import.ts`

```typescript
import type { ImportStage, SourcePlatform } from "@chat-exporter/shared";

import { importChatGptSharePage } from "./chatgpt-share-import.js";
import { importGenericSharePage } from "./generic-share-import.js";
import { classifySourcePlatform } from "./source-platform.js";

type StageCallback = (
  stage: Extract<ImportStage, "fetch" | "extract" | "normalize" | "structure">,
) => void;

export async function importSharePage(
  url: string,
  options?: {
    onStage?: StageCallback;
    sourcePlatform?: SourcePlatform;
  },
) {
  const sourcePlatform = options?.sourcePlatform ?? classifySourcePlatform(url);

  if (sourcePlatform === "chatgpt") {
    return importChatGptSharePage(url, {
      onStage: options?.onStage,
    });
  }

  return importGenericSharePage(url, {
    onStage: options?.onStage,
    sourcePlatform,
  });
}
```

### Target Design

Replace the if/else with a parser registry. Platforms with dedicated parsers are registered in a Map. For unregistered platforms, fall back to the generic parser.

```typescript
import type { SourcePlatform } from "@chat-exporter/shared";
import type { PlatformParser, StageCallback } from "./parser-types.js";

import { importChatGptSharePage } from "./chatgpt-share-import.js";
import { importGenericSharePage } from "./generic-share-import.js";
import { classifySourcePlatform } from "./source-platform.js";

/** Registry of platform-specific parsers. Platforms not in this map use the generic fallback. */
const parserRegistry = new Map<SourcePlatform, PlatformParser>([
  ["chatgpt", importChatGptSharePage],
]);

export async function importSharePage(
  url: string,
  options?: {
    onStage?: StageCallback;
    sourcePlatform?: SourcePlatform;
  },
) {
  const sourcePlatform = options?.sourcePlatform ?? classifySourcePlatform(url);
  const parser = parserRegistry.get(sourcePlatform);

  if (parser) {
    return parser(url, { onStage: options?.onStage });
  }

  return importGenericSharePage(url, {
    onStage: options?.onStage,
    sourcePlatform,
  });
}
```

### Key Changes

1. Import `StageCallback` from `./parser-types.js` instead of redefining it locally
2. Import `PlatformParser` type from `./parser-types.js`
3. Create `parserRegistry` Map with chatgpt as the only entry for now
4. Replace the if/else with a registry lookup + fallback
5. Remove the local `StageCallback` type definition

