 1→import type { NormalizedSnapshotPayload } from "@chat-exporter/shared";
 2→import type { BrowserContext, Page } from "playwright";
 3→import { DOM_KIT_SCRIPT } from "./parser-dom-kit.js";
 4→
 5→/** Block image, media, and font requests to reduce bandwidth. */
 6→export async function blockNonEssentialResources(
 7→  context: BrowserContext,
 8→): Promise<void> {
 9→  await context.route("**/*", (route) => {
10→    const resourceType = route.request().resourceType();
11→    if (
12→      resourceType === "image" ||
13→      resourceType === "media" ||
14→      resourceType === "font"
15→    ) {
16→      return route.abort();
17→    }
18→    return route.continue();
19→  });
20→}
21→
22→/** Inject safety polyfill (__name) and DOM parsing kit into page. */
23→export async function preparePageScripts(page: Page): Promise<void> {
24→  await page.addInitScript({
25→    content: "globalThis.__name = (value) => value;",
26→  });
27→  await page.addInitScript({ content: DOM_KIT_SCRIPT });
28→}
29→
30→/** Truncate messages if they exceed the limit, adding a warning. Returns mutated payload. */
31→export function truncateMessagesIfNeeded(
32→  payload: NormalizedSnapshotPayload,
33→  maxCount: number,
34→): NormalizedSnapshotPayload {
35→  if (payload.messages.length > maxCount) {
36→    const originalCount = payload.messages.length;
37→    payload.messages = payload.messages.slice(-maxCount);
38→    payload.warnings.push(
39→      `Nachrichtenlimit überschritten: ${originalCount} Nachrichten gefunden, auf die letzten ${maxCount} gekürzt.`,
40→    );
41→  }
42→  return payload;
43→}
44→
45→/** Validate raw HTML size against limit. Returns byte size. Throws if exceeded. */
46→export function validateRawHtmlSize(rawHtml: string, maxBytes: number): number {
47→  const rawHtmlBytes = Buffer.byteLength(rawHtml, "utf8");
48→  if (rawHtmlBytes > maxBytes) {
49→    const sizeMb = (rawHtmlBytes / (1024 * 1024)).toFixed(1);
50→    const limitMb = (maxBytes / (1024 * 1024)).toFixed(1);
51→    throw new Error(
52→      `HTML-Größe überschritten: ${sizeMb} MB (Limit: ${limitMb} MB).`,
53→    );
54→  }
55→  return rawHtmlBytes;
56→}
