117→function normalizeHostname(hostname: string) {
118→  return hostname.toLowerCase().replace(/^www\./, "");
119→}
120→
121→function isGoogleConsentUrl(urlString: string) {
122→  const url = new URL(urlString);
123→  const hostname = normalizeHostname(url.hostname);
124→
125→  return (
126→    hostname === "consent.google.com" ||
127→    hostname.endsWith(".consent.google.com")
128→  );
129→}
130→
131→function isGoogleSourcePlatform(sourcePlatform: SourcePlatform) {
132→  return sourcePlatform === "gemini" || sourcePlatform === "notebooklm";
133→}
