135→function looksLikeGoogleConsentContent(title: string, previewText: string) {
136→  const normalizedTitle = title.trim().toLowerCase();
137→  const normalizedPreview = previewText.trim().toLowerCase();
138→
139→  return (
140→    normalizedTitle === "before you continue" ||
141→    (normalizedPreview.includes("we use cookies") &&
142→      normalizedPreview.includes("accept all") &&
143→      normalizedPreview.includes("reject all"))
144→  );
145→}
