147→async function maybeDismissGoogleConsentGate(page: Page) {
148→  if (!isGoogleConsentUrl(page.url())) {
149→    return false;
150→  }
151→
152→  await page
153→    .waitForSelector('button[jsname="tWT92d"], button[jsname="b3VHJd"]', {
154→      state: "visible",
155→      timeout: GOOGLE_CONSENT_BUTTON_TIMEOUT_MS,
156→    })
157→    .catch(() => undefined);
158→
159→  const rejectAllButton = page.locator('button[jsname="tWT92d"]').first();
160→  const acceptAllButton = page.locator('button[jsname="b3VHJd"]').first();
161→
162→  let actionButton = rejectAllButton;
163→
164→  if (!(await actionButton.isVisible().catch(() => false))) {
165→    actionButton = acceptAllButton;
166→  }
167→
168→  if (!(await actionButton.isVisible().catch(() => false))) {
169→    return false;
170→  }
171→
172→  await actionButton.click();
173→
174→  for (
175→    let attempt = 0;
176→    attempt < GOOGLE_CONSENT_DISMISS_MAX_ATTEMPTS;
177→    attempt += 1
178→  ) {
179→    if (!isGoogleConsentUrl(page.url())) {
180→      await page
181→        .waitForLoadState("domcontentloaded", {
182→          timeout: GOOGLE_CONSENT_REDIRECT_TIMEOUT_MS,
183→        })
184→        .catch(() => undefined);
185→      return true;
186→    }
187→
188→    await page.waitForTimeout(GOOGLE_CONSENT_POLLING_INTERVAL_MS);
189→  }
190→
191→  return !isGoogleConsentUrl(page.url());
192→}
