 6→
 7→/** Callback for reporting import stage progress. */
 8→export type StageCallback = (
 9→  stage: Extract<ImportStage, "fetch" | "extract" | "normalize" | "structure">,
10→) => void;
11→
12→/** Standardized result returned by every platform parser. */
13→export type PlatformParserResult = {
14→  conversation: Conversation;
15→  warnings: string[];
16→  snapshot: {
17→    finalUrl: string;
18→    fetchedAt: string;
19→    pageTitle: string;
