  26→export const GOOGLE_NAVIGATION_TIMEOUT_MS = 60_000;
  27→
  28→/** Navigation timeout for non-Google platform pages. */
  29→export const DEFAULT_NAVIGATION_TIMEOUT_MS = 30_000;
  30→
  31→/** Timeout for domcontentloaded after consent dismiss / initial load. */
  32→export const DOM_CONTENT_LOADED_TIMEOUT_MS = 20_000;
