  36→
  37→/** Extra delay after network-idle to let JS-rendered content settle. */
  38→export const PAGE_STABILIZATION_DELAY_MS = 1_200;
  39→
  40→/** Timeout for the waitForFunction that checks for meaningful content. */
  41→export const FUNCTION_WAIT_TIMEOUT_MS = 20_000;
  42→
  43→/* ── Consent Handling ─────────────────────────────────────── */
  44→
  45→/** Maximum polling iterations when waiting for navigation after consent dismiss. */
  46→export const GOOGLE_CONSENT_DISMISS_MAX_ATTEMPTS = 60;
  47→
  48→/** Polling interval (ms) between checks after clicking the consent button. */
  49→export const GOOGLE_CONSENT_POLLING_INTERVAL_MS = 250;
  50→
  51→/** Timeout for domcontentloaded after Google consent redirect. */
  52→export const GOOGLE_CONSENT_REDIRECT_TIMEOUT_MS = 15_000;
