  54→/* ── Content Thresholds ───────────────────────────────────── */
  55→
  56→/** Minimum text length to consider an extraction root meaningful. */
  57→export const MIN_CONTENT_TEXT_LENGTH = 32;
  58→
  59→/** Minimum direct children for a container to be scored. */
  60→export const MIN_MEANINGFUL_CHILDREN = 2;
  61→
  62→/** Minimum text length for a child to count as meaningful. */
  63→export const MIN_CHILD_TEXT_LENGTH = 2;
  64→
  65→/** Text length threshold above which a child is meaningful without blocks. */
  66→export const MIN_TEXT_LENGTH_FOR_MEANINGFUL_CHILDREN = 40;
  67→
  68→/** Maximum children sampled for scoring a container. */
  69→export const MAX_SAMPLE_CHILDREN = 48;
  70→
  71→/** Per-child text length cap used in average-text-length calculation. */
  72→export const MAX_TEXT_LENGTH_FOR_AVERAGING = 4_000;
  73→
  74→/** Maximum container candidates to evaluate. */
  75→export const MAX_CONTAINER_CANDIDATES = 500;
