  77→/* ── Scoring Weights ──────────────────────────────────────── */
  78→
  79→export const SCORE_CHILDREN_WEIGHT = 16;
  80→export const SCORE_TAG_RATIO_WEIGHT = 12;
  81→export const SCORE_HINTED_WEIGHT = 8;
  82→export const SCORE_BLOCK_WEIGHT = 4;
  83→export const SCORE_ACTION_WEIGHT = 2;
  84→export const SCORE_AVG_TEXT_DIVISOR = 35;
  85→export const SCORE_AVG_TEXT_MAX = 16;
  86→export const SCORE_DEPTH_PENALTY = 1.5;
  87→export const SCORE_FORM_PENALTY = 10;
  88→
  89→/** Dedup: skip candidate whose text is >= this fraction of root text. */
  90→export const CANDIDATE_DEDUP_THRESHOLD = 0.95;
  91→
