  93→export const MIN_CONTAINER_SCORE_THRESHOLD = 42;
  94→
  95→/* ── Fallback ─────────────────────────────────────────────── */
  96→
  97→/** Minimum text length for a fallback message candidate. */
  98→export const MIN_FALLBACK_TEXT_LENGTH = 12;
  99→
 100→/** Maximum text length for a fallback message candidate. */
