 118→
 119→function normalizeHostname(hostname: string) {
 120→  return hostname.toLowerCase().replace(/^www\./, "");
 121→}
 122→
 123→function isGoogleConsentUrl(urlString: string) {
 124→  const url = new URL(urlString);
 125→  const hostname = normalizeHostname(url.hostname);
 126→
 127→  return (
 128→    hostname === "consent.google.com" ||
 129→    hostname.endsWith(".consent.google.com")
 130→  );
 131→}
 132→
 133→function isGoogleSourcePlatform(sourcePlatform: SourcePlatform) {
 134→  return sourcePlatform === "gemini" || sourcePlatform === "notebooklm";
 135→}
 136→
 137→function looksLikeGoogleConsentContent(title: string, previewText: string) {
 138→  const normalizedTitle = title.trim().toLowerCase();
 139→  const normalizedPreview = previewText.trim().toLowerCase();
 140→
 141→  return (
 142→    normalizedTitle === "before you continue" ||
 143→    (normalizedPreview.includes("we use cookies") &&
 144→      normalizedPreview.includes("accept all") &&
 145→      normalizedPreview.includes("reject all"))
 146→  );
 147→}
