 149→async function maybeDismissGoogleConsentGate(page: Page) {
 150→  if (!isGoogleConsentUrl(page.url())) {
 151→    return false;
 152→  }
 153→
 154→  await page
 155→    .waitForSelector('button[jsname="tWT92d"], button[jsname="b3VHJd"]', {
 156→      state: "visible",
 157→      timeout: GOOGLE_CONSENT_BUTTON_TIMEOUT_MS,
 158→    })
 159→    .catch(() => undefined);
 160→
 161→  const rejectAllButton = page.locator('button[jsname="tWT92d"]').first();
 162→  const acceptAllButton = page.locator('button[jsname="b3VHJd"]').first();
 163→
 164→  let actionButton = rejectAllButton;
 165→
 166→  if (!(await actionButton.isVisible().catch(() => false))) {
 167→    actionButton = acceptAllButton;
 168→  }
 169→
 170→  if (!(await actionButton.isVisible().catch(() => false))) {
 171→    return false;
 172→  }
 173→
 174→  await actionButton.click();
 175→
 176→  for (
 177→    let attempt = 0;
 178→    attempt < GOOGLE_CONSENT_DISMISS_MAX_ATTEMPTS;
 179→    attempt += 1
 180→  ) {
 181→    if (!isGoogleConsentUrl(page.url())) {
 182→      await page
 183→        .waitForLoadState("domcontentloaded", {
 184→          timeout: GOOGLE_CONSENT_REDIRECT_TIMEOUT_MS,
 185→        })
 186→        .catch(() => undefined);
 187→      return true;
 188→    }
 189→
 190→    await page.waitForTimeout(GOOGLE_CONSENT_POLLING_INTERVAL_MS);
 191→  }
 192→
 193→  return !isGoogleConsentUrl(page.url());
 194→}
