 196→export async function importGenericSharePage(
 197→  url: string,
 198→  options: {
 199→    onStage?: StageCallback;
 200→    sourcePlatform: SourcePlatform;
 201→  },
 202→) {
 203→  const context = await acquireContext();
 204→
 205→  try {
 206→    if (!isGoogleSourcePlatform(options.sourcePlatform)) {
 207→      await blockNonEssentialResources(context);
 208→    }
 209→
 210→    const page = await context.newPage();
 211→    await preparePageScripts(page);
 212→
 213→    const navigationTimeout = isGoogleSourcePlatform(options.sourcePlatform)
 214→      ? GOOGLE_NAVIGATION_TIMEOUT_MS
 215→      : DEFAULT_NAVIGATION_TIMEOUT_MS;
 216→
 217→    options.onStage?.("fetch");
 218→    await page.goto(url, {
 219→      waitUntil: "commit",
 220→      timeout: navigationTimeout,
 221→    });
 222→    await page
 223→      .waitForLoadState("domcontentloaded", {
 224→        timeout: DOM_CONTENT_LOADED_TIMEOUT_MS,
 225→      })
 226→      .catch(() => undefined);
 227→
 228→    if (isGoogleSourcePlatform(options.sourcePlatform)) {
 229→      await maybeDismissGoogleConsentGate(page);
 230→    }
 231→
 232→    if (isGoogleConsentUrl(page.url())) {
 233→      throw new Error(
 234→        `Google showed a cookie consent gate instead of the ${options.sourcePlatform} share page.`,
 235→      );
 236→    }
 237→
 238→    await page
 239→      .waitForFunction(
 240→        () => {
 241→          const root =
 242→            document.querySelector("main, [role='main'], article, body") ??
 243→            document.body;
 244→          return (root.textContent ?? "").trim().length > 32;
 245→        },
 246→        {
 247→          timeout: FUNCTION_WAIT_TIMEOUT_MS,
 248→        },
 249→      )
 250→      .catch(() => undefined);
 251→
 252→    await page
 253→      .waitForLoadState("networkidle", {
 254→        timeout: NETWORK_IDLE_TIMEOUT_MS,
 255→      })
 256→      .catch(() => undefined);
 257→    await page.waitForTimeout(PAGE_STABILIZATION_DELAY_MS);
 258→
 259→    options.onStage?.("extract");
 260→    const extractionConfig = {
 261→      MIN_CONTENT_TEXT_LENGTH,
