 389→            }
 390→
 391→            if (child.querySelector("nav,header,footer,aside,form,dialog")) {
 392→              return false;
 393→            }
 394→
 395→            const textLength = textContentLength(child);
 396→            if (textLength < cfg.MIN_CHILD_TEXT_LENGTH) {
