 426→                Math.min(
 427→                  textContentLength(child),
 428→                  cfg.MAX_TEXT_LENGTH_FOR_AVERAGING,
 429→                ),
 430→              0,
 431→            ) / sampleChildren.length;
 432→          const blockHeavyCount = sampleChildren.filter(
