 462→              repeatedTagRatio * cfg.SCORE_TAG_RATIO_WEIGHT +
 463→              hintedCount * cfg.SCORE_HINTED_WEIGHT +
 464→              blockHeavyCount * cfg.SCORE_BLOCK_WEIGHT +
 465→              actionBarCount * cfg.SCORE_ACTION_WEIGHT +
 466→              Math.min(
 467→                avgTextLength / cfg.SCORE_AVG_TEXT_DIVISOR,
 468→                cfg.SCORE_AVG_TEXT_MAX,
 469→              ) -
 470→              elementDepth(element) * cfg.SCORE_DEPTH_PENALTY -
 471→              formPenalty * cfg.SCORE_FORM_PENALTY,
