 476→        function dedupeCandidates(
 477→          elements: Element[],
 478→          maxRootTextLength: number,
 479→        ) {
 480→          const sorted = Array.from(new Set(elements)).sort(
 481→            (left, right) => elementDepth(right) - elementDepth(left),
 482→          );
 483→          const unique: Element[] = [];
 484→          const seenText = new Set<string>();
 485→
 486→          for (const element of sorted) {
 487→            if (!isVisible(element) || isExcluded(element)) {
 488→              continue;
 489→            }
 490→
 491→            const text = normalizeWhitespace(
 492→              (element as HTMLElement).innerText,
 493→            );
 494→            if (!text) {
 495→              continue;
 496→            }
 497→
 498→            if (
 499→              text.length >=
 500→              maxRootTextLength * cfg.CANDIDATE_DEDUP_THRESHOLD
 501→            ) {
 502→              continue;
 503→            }
 504→
 505→            if (seenText.has(text)) {
 506→              continue;
 507→            }
 508→
 509→            if (
 510→              unique.some(
 511→                (existing) =>
 512→                  existing.contains(element) || element.contains(existing),
 513→              )
 514→            ) {
 515→              continue;
 516→            }
 517→
 518→            unique.push(element);
 519→            seenText.add(text);
 520→          }
 521→
 522→          return unique.reverse();
 523→        }
 524→
 525→        function contentRootFor(element: Element) {
 526→          return (
 527→            element.querySelector(
 528→              ".markdown, [data-testid*='markdown'], [class*='markdown'], [data-testid*='response-content'], [data-testid*='message-content'], [data-message-content]",
 529→            ) ?? element
 530→          );
 531→        }
