 542→            hints.push(attributeHintText(current));
 543→            current = current.parentElement;
 544→          }
 545→
 546→          hints.push(
 547→            Array.from(element.querySelectorAll("[class]"))
 548→              .slice(0, cfg.MAX_HINT_CLASSES)
 549→              .map((node) => ((node as HTMLElement).className || "").toString())
 550→              .join(" ")
 551→              .toLowerCase(),
 552→          );
 553→
 554→          const hintText = hints.join(" ");
 555→
 556→          if (
 557→            /(^|\b)(user|human|prompt|question|author-user|from-user|self-end|justify-end|ml-auto|text-right|end-)(\b|$)/.test(
 558→              hintText,
 559→            )
 560→          ) {
 561→            return "user" as const;
 562→          }
 563→
 564→          if (
 565→            /(^|\b)(assistant|model|bot|claude|gemini|grok|deepseek|notebooklm|response|answer|self-start|justify-start|mr-auto|text-left|start-)(\b|$)/.test(
 566→              hintText,
 567→            )
 568→          ) {
 569→            return "assistant" as const;
 570→          }
