 575→        function roleFromLayout(element: Element, root: Element) {
 576→          const rootRect = (root as HTMLElement).getBoundingClientRect();
 577→          const target =
 578→            (element.querySelector(
 579→              "p,pre,ul,ol,blockquote,table,h1,h2,h3,h4,h5,h6",
 580→            ) as HTMLElement | null) ?? (element as HTMLElement);
 581→          const rect = target.getBoundingClientRect();
 582→
 583→          if (rootRect.width <= 0 || rect.width <= 0) {
 584→            return null;
 585→          }
 586→
 587→          const centerRatio =
 588→            (rect.left + rect.width / 2 - rootRect.left) /
 589→            Math.max(rootRect.width, 1);
 590→
 591→          if (centerRatio >= 0.62) {
 592→            return "user" as const;
 593→          }
 594→
 595→          if (centerRatio <= 0.38) {
 596→            return "assistant" as const;
 597→          }
 598→
 599→          return null;
 600→        }
