 638→          const messages: Array<{
 639→            id: string;
 640→            role: "user" | "assistant";
 641→            rawText: string;
 642→            rawHtml: string;
 643→            blocks: Array<Record<string, unknown>>;
 644→            parser: {
 645→              source: string;
 646→              blockCount: number;
 647→              usedFallback: boolean;
 648→              strategy: "deterministic" | "fallback";
 649→            };
 650→          }> = [];
 651→
 652→          turnElements.forEach((turnElement, index) => {
 653→            const turnId =
 654→              turnElement.getAttribute("data-turn-id") ??
 655→              `gemini-turn-${index + 1}`;
 656→            const userElement =
 657→              turnElement.querySelector("user-query .user-query-container") ??
 658→              turnElement.querySelector(".user-query-container");
 659→            const responseElement =
 660→              turnElement.querySelector(
 661→                "response-container .response-container-with-gpi, response-container",
 662→              ) ?? turnElement.querySelector("response-container");
