 670→                id: `${turnId}-user`,
 671→                role: "user" as const,
 672→                rawText: userText,
 673→                rawHtml: (userElement as HTMLElement).innerHTML,
 674→                blocks: [{ type: "paragraph", text: userText }],
 675→                parser: {
 676→                  source: "gemini-user-query",
 677→                  blockCount: 1,
 678→                  usedFallback: false,
 679→                  strategy: "deterministic" as const,
 680→                },
 681→              });
