 717→              id: `${turnId}-assistant`,
 718→              role: "assistant" as const,
 719→              rawText: responseText,
 720→              rawHtml: (responseRoot as HTMLElement).innerHTML,
 721→              blocks: finalBlocks,
 722→              parser: {
 723→                source:
 724→                  responseBlocks.length > 0
 725→                    ? "gemini-response-container"
 726→                    : "gemini-response-fallback",
 727→                blockCount: finalBlocks.length,
 728→                usedFallback: responseBlocks.length === 0,
 729→                strategy:
 730→                  responseBlocks.length > 0
 731→                    ? ("deterministic" as const)
 732→                    : ("fallback" as const),
 733→              },
 734→            });
 735→          });
