 795→            ),
 796→            ...Array.from(extractionRoot.querySelectorAll("[data-message-id]")),
 797→            ...Array.from(
 798→              extractionRoot.querySelectorAll(
 799→                "[data-testid*='conversation-turn']",
 800→              ),
 801→            ),
 802→            ...Array.from(
 803→              extractionRoot.querySelectorAll("[data-testid*='chat-turn']"),
 804→            ),
 805→            ...Array.from(
 806→              extractionRoot.querySelectorAll("[data-testid*='message']"),
