 861→        const parsedMessages: Array<{
 862→          id: string;
 863→          role: "user" | "assistant" | "unknown";
 864→          rawText: string;
 865→          rawHtml: string;
 866→          blocks: Array<Record<string, unknown>>;
 867→          parser: {
 868→            source: string;
 869→            blockCount: number;
 870→            usedFallback: boolean;
 871→            strategy: "deterministic" | "fallback";
 872→          };
