 948→          }
 949→        } else {
 950→          for (let index = firstResolvedIndex - 1; index >= 0; index -= 1) {
 951→            resolvedRoles[index] = oppositeRole(
 952→              resolvedRoles[index + 1] as "user" | "assistant",
 953→            );
 954→          }
 955→
 956→          for (
 957→            let index = firstResolvedIndex + 1;
 958→            index < resolvedRoles.length;
 959→            index += 1
 960→          ) {
 961→            if (!resolvedRoles[index]) {
 962→              resolvedRoles[index] = oppositeRole(
 963→                resolvedRoles[index - 1] as "user" | "assistant",
 964→              );
 965→            }
 966→          }
 967→        }
 968→
 969→        let inferredRoleCount = 0;
 970→        const messages = parsedMessages.map((message, index) => {
 971→          const resolvedRole = resolvedRoles[index] ?? "unknown";
 972→
 973→          if (message.role === "unknown" && resolvedRole !== "unknown") {
 974→            inferredRoleCount += 1;
 975→          }
 976→
 977→          return {
 978→            ...message,
 979→            role: resolvedRole,
 980→          };
 981→        });
 982→
 983→        if (inferredRoleCount > 0) {
 984→          warnings.push(
 985→            `${inferredRoleCount} message role(s) were inferred from layout or turn order because the page did not expose explicit author markers.`,
 986→          );
 987→        }
 988→
 989→        return {
 990→          title: normalizeTitle(document.title),
 991→          messages,
 992→          warnings,
 993→        };
 994→      },
 995→      { platform: options.sourcePlatform, cfg: extractionConfig },
 996→    );
 997→
 998→    options.onStage?.("normalize");
 999→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
1000→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
1001→
1002→    const previewText = normalizedPayload.messages
1003→      .slice(0, 3)
1004→      .flatMap((message) =>
1005→        message.blocks
1006→          .map((block) => {
1007→            switch (block.type) {
1008→              case "paragraph":
1009→              case "quote":
1010→              case "code":
1011→                return block.text;
1012→              case "heading":
1013→                return block.text;
1014→              case "list":
1015→                return block.items.join(" ");
1016→              case "table":
1017→                return [...block.headers, ...block.rows.flat()].join(" ");
1018→              default:
1019→                return undefined;
1020→            }
1021→          })
1022→          .filter(Boolean),
1023→      )
1024→      .join(" ")
1025→      .slice(0, MAX_PREVIEW_TEXT_LENGTH);
1026→
1027→    if (
1028→      isGoogleSourcePlatform(options.sourcePlatform) &&
1029→      looksLikeGoogleConsentContent(normalizedPayload.title, previewText)
1030→    ) {
1031→      throw new Error(
1032→        `Google returned a cookie consent screen instead of the ${options.sourcePlatform} conversation.`,
1033→      );
1034→    }
1035→
1036→    if (normalizedPayload.messages.length === 0) {
1037→      throw new Error(
1038→        `No importable messages were detected on this ${options.sourcePlatform} page.`,
1039→      );
1040→    }
1041→
1042→    options.onStage?.("structure");
1043→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
1044→    const warnings = [...normalizedPayload.warnings, ...structured.warnings];
1045→
1046→    if (!looksLikeSharedConversationUrl(url)) {
1047→      warnings.push(
1048→        "The URL does not look like a typical public share page path, so extraction may be noisier than usual.",
1049→      );
1050→    }
1051→
1052→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
1053→      ...normalizedPayload,
1054→      messages: structured.messages,
1055→      warnings,
1056→      structuring: structured.structuring,
1057→    });
1058→    const rawHtml = await page.content();
1059→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
1060→    const fetchedAt = new Date().toISOString();
1061→
1062→    const conversation = conversationSchema.parse({
1063→      id: crypto.randomUUID(),
1064→      title: finalPayload.title,
1065→      source: {
1066→        url,
1067→        platform: options.sourcePlatform,
1068→      },
1069→      messages: finalPayload.messages,
1070→    });
1071→
1072→    return {
1073→      conversation,
1074→      warnings: finalPayload.warnings,
1075→      snapshot: {
1076→        finalUrl: page.url(),
1077→        fetchedAt,
1078→        pageTitle: finalPayload.title,
1079→        rawHtml,
1080→        normalizedPayload: finalPayload,
1081→        fetchMetadata: {
1082→          articleCount: normalizedPayload.messages.length,
1083→          messageCount: conversation.messages.length,
1084→          rawHtmlBytes,
1085→        },
1086→      },
1087→    };
1088→  } finally {
1089→    await releaseContext(context);
1090→  }
1091→}
