## Task: Phase 2 — Create Claude Share Page Parser

Create a dedicated parser for Claude AI share pages (`https://claude.ai/share/{id}`).

### Research: Claude Share Page DOM Structure

First, research the Claude share page DOM structure. Try to web-search for information about Claude share page HTML structure, selectors, and data attributes.

Known expectations:
- Claude share pages use `[data-testid]`-based attributes for key elements
- Turn containers likely have role information
- The page title usually starts with "Claude" prefix that needs to be removed

If you can't find specific DOM details via research, implement a reasonable parser based on common patterns:
- Look for `[data-testid*="conversation-turn"]` or similar patterns
- Look for role attributes or data attributes indicating user/assistant
- Use `.markdown` or similar class for formatted assistant content
- Fall back to container-based extraction

### File to create

`apps/server/src/lib/claude-share-import.ts`

### Implementation Pattern

Follow the exact same pattern as the ChatGPT parser and Gemini parser:

```typescript
import {
  conversationSchema,
  normalizedSnapshotPayloadSchema,
} from "@chat-exporter/shared";
import { acquireContext, releaseContext } from "./browser-pool.js";
import { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
import { applyOpenAiStructuring } from "./openai-structuring.js";
import type { PlatformParserResult, StageCallback } from "./parser-types.js";
import {
  blockNonEssentialResources,
  preparePageScripts,
  truncateMessagesIfNeeded,
  validateRawHtmlSize,
} from "./parser-page-utils.js";

/* Constants */
export const PAGE_LOAD_TIMEOUT_MS = 30_000;
export const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
export const PAGE_STABILIZATION_MS = 1_000;

export async function importClaudeSharePage(
  url: string,
  options?: { onStage?: StageCallback },
): Promise<PlatformParserResult> {
  const context = await acquireContext();
  try {
    await blockNonEssentialResources(context);
    const page = await context.newPage();
    await preparePageScripts(page);

    options?.onStage?.("fetch");
    await page.goto(url, { waitUntil: "domcontentloaded", timeout: PAGE_LOAD_TIMEOUT_MS });
    // Wait for conversation content to appear
    await page.waitForFunction(
      () => {
        const root = document.querySelector("main, [role='main'], article, body") ?? document.body;
        return (root.textContent ?? "").trim().length > 32;
      },
      { timeout: MESSAGE_WAIT_TIMEOUT_MS },
    );
    await page.waitForTimeout(PAGE_STABILIZATION_MS);

    options?.onStage?.("extract");
    const extracted = await page.evaluate(() => {
      const { normalizeWhitespace, elementToBlocks, inlineFromElement } = globalThis.__domKit;

      function normalizeTitle(rawTitle: string) {
        return rawTitle.replace(/^Claude\s*[-–—|]\s*/i, "").trim() || "Untitled Chat";
      }

      const warnings: string[] = [];

      // Strategy 1: Look for data-testid based turn containers
      // Claude share pages typically use [data-testid] patterns
      const turnSelectors = [
        '[data-testid*="conversation-turn"]',
        '[data-testid*="chat-turn"]',
        '[data-testid*="message"]',
        '.conversation-turn',
        '.chat-message',
      ];

      let turnElements: Element[] = [];
      for (const selector of turnSelectors) {
        turnElements = Array.from(document.querySelectorAll(selector));
        if (turnElements.length >= 2) break;
      }

      // Strategy 2: If no explicit turns found, look for alternating content containers
      if (turnElements.length < 2) {
        // Claude may use a simpler structure with role-based containers
        const humanMessages = document.querySelectorAll('[class*="human"], [class*="user"], [data-role="human"], [data-role="user"]');
        const assistantMessages = document.querySelectorAll('[class*="assistant"], [data-role="assistant"]');

        if (humanMessages.length > 0 || assistantMessages.length > 0) {
          // Collect all with ordering
          const allMessages = Array.from(document.querySelectorAll(
            '[class*="human"], [class*="user"], [data-role="human"], [data-role="user"], [class*="assistant"], [data-role="assistant"]'
          ));
          turnElements = allMessages;
        }
      }

      // Strategy 3: Content-based heuristic
      if (turnElements.length < 2) {
        // Look for the main content area and find direct children that look like messages
        const mainContent = document.querySelector('main, [role="main"], .conversation, .chat-content');
        if (mainContent) {
          const candidates = Array.from(mainContent.children).filter(child => {
            const text = (child.textContent ?? "").trim();
            return text.length > 5 && child.children.length > 0;
          });
          if (candidates.length >= 2) {
            turnElements = candidates;
            warnings.push("Used content heuristic to identify messages — extraction quality may vary.");
          }
        }
      }

      if (turnElements.length === 0) {
        return { title: normalizeTitle(document.title), messages: [], warnings: ["No conversation turns found on Claude share page."] };
      }

      let fallbackCount = 0;
      const messages = turnElements.map((turn, index) => {
        // Determine role
        const testId = turn.getAttribute("data-testid") ?? "";
