            rawHtml: (turn as HTMLElement).innerHTML,
            blocks: [{ type: "paragraph" as const, text: rawText }],
            parser: { source: "claude-fallback", blockCount: 1, usedFallback: true, strategy: "fallback" as const },
          };
        }

        if (blocks.length === 0) return null;

        return {
          id: messageId,
