  7→import { applyOpenAiStructuring } from "./openai-structuring.js";
  8→import {
  9→  blockNonEssentialResources,
 10→  preparePageScripts,
 11→  truncateMessagesIfNeeded,
 12→  validateRawHtmlSize,
 13→} from "./parser-page-utils.js";
 14→import type { PlatformParserResult, StageCallback } from "./parser-types.js";
 15→
 16→/* ── ChatGPT share-import constants ─────────────────────────── */
 17→
 18→/** Timeout for the initial page.goto() navigation. */
 19→export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 20→
 21→/** Timeout for waiting until message elements appear in the DOM. */
 22→export const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
 23→
 24→/** Extra delay after messages appear to let the page stabilize. */
 25→export const PAGE_STABILIZATION_MS = 800;
 26→
 27→/** CSS selector that identifies ChatGPT share-page message elements. */
 28→export const CHATGPT_SHARE_SELECTOR = "article [data-message-author-role]";
 29→
 30→/* ─────────────────────────────────────────────────────────── */
 31→
 32→export async function importChatGptSharePage(
 33→  url: string,
 34→  options?: {
 35→    onStage?: StageCallback;
 36→  },
 37→): Promise<PlatformParserResult> {
 38→  const context = await acquireContext();
 39→
 40→  try {
 41→    await blockNonEssentialResources(context);
 42→
 43→    const page = await context.newPage();
 44→    await preparePageScripts(page);
 45→
 46→    options?.onStage?.("fetch");
 47→    await page.goto(url, {
 48→      waitUntil: "domcontentloaded",
 49→      timeout: PAGE_LOAD_TIMEOUT_MS,
 50→    });
 51→    await page.waitForFunction(
 52→      (selector) => document.querySelectorAll(selector).length > 0,
 53→      CHATGPT_SHARE_SELECTOR,
 54→      {
 55→        timeout: MESSAGE_WAIT_TIMEOUT_MS,
 56→      },
 57→    );
 58→    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 59→
 60→    options?.onStage?.("extract");
 61→    const extracted = await page.evaluate(() => {
 62→      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 63→
 64→      function normalizeTitle(rawTitle: string) {
 65→        const title = rawTitle.replace(/^ChatGPT\s*-\s*/i, "").trim();
 66→        return title || "Untitled Chat";
 67→      }
 68→
 69→      const warnings: string[] = [];
 70→      const articles = Array.from(document.querySelectorAll("article"));
 71→      let fallbackCount = 0;
 72→
 73→      const messages = articles
 74→        .map((article) => {
 75→          const messageElement = article.querySelector(
 76→            "[data-message-author-role]",
 77→          ) as HTMLElement | null;
 78→          if (!messageElement) {
 79→            return null;
 80→          }
 81→
 82→          const role =
 83→            messageElement.getAttribute("data-message-author-role") ??
 84→            "unknown";
 85→          const messageId =
 86→            messageElement.getAttribute("data-message-id") ??
 87→            crypto.randomUUID();
 88→
 89→          if (role === "assistant") {
 90→            const markdownRoot =
 91→              (messageElement.querySelector(
 92→                ".markdown",
 93→              ) as HTMLElement | null) ?? messageElement;
 94→            const blocks = Array.from(markdownRoot.childNodes).flatMap(
 95→              (childNode) => {
 96→                if (childNode.nodeType === Node.TEXT_NODE) {
 97→                  const text = normalizeWhitespace(childNode.textContent ?? "");
 98→                  return text ? [{ type: "paragraph" as const, text }] : [];
 99→                }
100→
101→                if (childNode.nodeType !== Node.ELEMENT_NODE) {
102→                  return [];
103→                }
104→
105→                return elementToBlocks(childNode as Element);
106→              },
107→            );
108→
109→            const rawText = normalizeWhitespace(messageElement.innerText);
110→            const rawHtml = messageElement.innerHTML;
111→
112→            if (blocks.length === 0) {
113→              fallbackCount += 1;
114→              return rawText
115→                ? {
116→                    id: messageId,
117→                    role,
118→                    rawText,
119→                    rawHtml,
120→                    blocks: [{ type: "paragraph" as const, text: rawText }],
121→                    parser: {
122→                      source: "assistant-fallback",
123→                      blockCount: 1,
124→                      usedFallback: true,
125→                      strategy: "fallback" as const,
126→                    },
127→                  }
128→                : null;
129→            }
130→
131→            return {
132→              id: messageId,
133→              role,
134→              rawText,
135→              rawHtml,
136→              blocks,
137→              parser: {
138→                source: "assistant-markdown",
139→                blockCount: blocks.length,
140→                usedFallback: false,
141→                strategy: "deterministic" as const,
142→              },
143→            };
144→          }
145→
146→          const textSource =
147→            (messageElement.querySelector(
148→              ".whitespace-pre-wrap",
149→            ) as HTMLElement | null) ?? messageElement;
150→          const text = normalizeWhitespace(textSource.innerText);
151→          const rawHtml = textSource.innerHTML;
152→
153→          return text
154→            ? {
155→                id: messageId,
156→                role,
157→                rawText: text,
158→                rawHtml,
159→                blocks: [{ type: "paragraph" as const, text }],
160→                parser: {
161→                  source:
162→                    textSource === messageElement
163→                      ? "user-message"
164→                      : "user-whitespace-pre-wrap",
165→                  blockCount: 1,
166→                  usedFallback: false,
167→                  strategy: "deterministic" as const,
168→                },
169→              }
170→            : null;
171→        })
172→        .filter(Boolean);
173→
174→      if (fallbackCount > 0) {
175→        warnings.push(
176→          `${fallbackCount} assistant message(s) fell back to a plain paragraph because no richer block structure was detected.`,
177→        );
178→      }
179→
180→      return {
181→        title: normalizeTitle(document.title),
182→        messages,
183→        warnings,
184→      };
185→    });
186→
187→    options?.onStage?.("normalize");
188→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
189→
190→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
191→
192→    options?.onStage?.("structure");
193→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
194→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
195→      ...normalizedPayload,
196→      messages: structured.messages,
197→      warnings: [...normalizedPayload.warnings, ...structured.warnings],
198→      structuring: structured.structuring,
199→    });
200→    const rawHtml = await page.content();
201→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
202→    const fetchedAt = new Date().toISOString();
203→
204→    const conversation = conversationSchema.parse({
205→      id: crypto.randomUUID(),
206→      title: finalPayload.title,
207→      source: {
208→        url,
209→        platform: "chatgpt",
210→      },
211→      messages: finalPayload.messages,
212→    });
213→
214→    return {
215→      conversation,
216→      warnings: finalPayload.warnings,
217→      snapshot: {
218→        finalUrl: page.url(),
219→        fetchedAt,
220→        pageTitle: finalPayload.title,
221→        rawHtml,
222→        normalizedPayload: finalPayload,
223→        fetchMetadata: {
224→          articleCount: normalizedPayload.messages.length,
225→          messageCount: conversation.messages.length,
226→          rawHtmlBytes,
227→        },
228→      },
229→    };
230→  } finally {
231→    await releaseContext(context);
232→  }
233→}
