306→
307→        if (userText) {
308→          messages.push({
309→            id: `${turnId}-user`,
310→            role: "user" as const,
311→            rawText: userText,
312→            rawHtml: (userElement as HTMLElement).innerHTML,
313→            blocks: [{ type: "paragraph", text: userText }],
314→            parser: {
315→              source: "gemini-user-query",
316→              blockCount: 1,
317→              usedFallback: false,
318→              strategy: "deterministic" as const,
319→            },
