 6→import { classifySourcePlatform } from "./source-platform.js";
 7→
 8→/** Registry of platform-specific parsers. Platforms not in this map use the generic fallback. */
 9→const parserRegistry = new Map<SourcePlatform, PlatformParser>([
10→  ["chatgpt", importChatGptSharePage as PlatformParser],
11→  ["gemini", importGeminiSharePage as PlatformParser],
12→]);
