14→export async function importSharePage(
15→  url: string,
16→  options?: {
17→    onStage?: StageCallback;
18→    sourcePlatform?: SourcePlatform;
19→  },
20→) {
21→  const sourcePlatform = options?.sourcePlatform ?? classifySourcePlatform(url);
22→  const parser = parserRegistry.get(sourcePlatform);
