200→        return Boolean(
201→          element.closest(
202→            "nav,header,footer,aside,form,dialog,[role='navigation'],[aria-hidden='true']",
203→          ),
204→        );
205→      }
206→
207→      function isVisible(element: Element) {
208→        const computed = globalThis.getComputedStyle(element as HTMLElement);
209→
210→        if (
211→          computed.display === "none" ||
212→          computed.visibility === "hidden" ||
213→          computed.opacity === "0"
214→        ) {
215→          return false;
216→        }
217→
218→        const rect = (element as HTMLElement).getBoundingClientRect();
219→        return rect.width > 0 && rect.height > 0;
220→      }
221→
222→      function contentRootFor(element: Element) {
223→        return (
224→          element.querySelector(
225→            ".markdown, [data-testid*='markdown'], [class*='markdown'], [data-testid*='response-content'], [data-testid*='message-content'], [data-message-content]",
226→          ) ?? element
227→        );
228→      }
229→
230→      function pickGeminiTitle() {
231→        const explicitTitle =
232→          document.querySelector(".share-landing-page_content h1") ??
233→          document.querySelector("main h1") ??
234→          document.querySelector("h1");
235→
236→        if (explicitTitle) {
237→          const title = normalizeWhitespace(
238→            (explicitTitle as HTMLElement).innerText,
239→          );
240→
241→          if (title) {
242→            return normalizeTitle(title);
243→          }
244→        }
245→
246→        return normalizeTitle(document.title);
247→      }
248→
249→      function normalizeGeminiUserQuery(text: string) {
250→        return normalizeWhitespace(text.replace(/^you said\s*/i, ""));
251→      }
252→
253→      const turnElements = Array.from(
254→        document.querySelectorAll(".share-turn-viewer"),
255→      ).filter((element) => isVisible(element) && !isExcluded(element));
256→
257→      if (turnElements.length === 0) {
258→        return {
259→          title: normalizeTitle(document.title),
260→          messages: [] as Array<{
261→            id: string;
262→            role: "user" | "assistant";
263→            rawText: string;
264→            rawHtml: string;
265→            blocks: Array<Record<string, unknown>>;
266→            parser: {
267→              source: string;
268→              blockCount: number;
269→              usedFallback: boolean;
270→              strategy: "deterministic" | "fallback";
271→            };
272→          }>,
273→          warnings: ["No Gemini share turn containers found on this page."],
274→        };
275→      }
276→
277→      const messages: Array<{
278→        id: string;
279→        role: "user" | "assistant";
280→        rawText: string;
281→        rawHtml: string;
282→        blocks: Array<Record<string, unknown>>;
283→        parser: {
284→          source: string;
285→          blockCount: number;
286→          usedFallback: boolean;
287→          strategy: "deterministic" | "fallback";
288→        };
289→      }> = [];
290→
291→      turnElements.forEach((turnElement, index) => {
292→        const turnId =
293→          turnElement.getAttribute("data-turn-id") ??
294→          `gemini-turn-${index + 1}`;
295→        const userElement =
296→          turnElement.querySelector("user-query .user-query-container") ??
297→          turnElement.querySelector(".user-query-container");
298→        const responseElement =
299→          turnElement.querySelector(
300→            "response-container .response-container-with-gpi, response-container",
301→          ) ?? turnElement.querySelector("response-container");
302→
303→        const userText = userElement
304→          ? normalizeGeminiUserQuery((userElement as HTMLElement).innerText)
305→          : "";
306→
307→        if (userText) {
308→          messages.push({
309→            id: `${turnId}-user`,
310→            role: "user" as const,
311→            rawText: userText,
312→            rawHtml: (userElement as HTMLElement).innerHTML,
313→            blocks: [{ type: "paragraph", text: userText }],
314→            parser: {
315→              source: "gemini-user-query",
316→              blockCount: 1,
317→              usedFallback: false,
318→              strategy: "deterministic" as const,
319→            },
320→          });
321→        }
322→
323→        if (!responseElement) {
324→          return;
325→        }
326→
327→        const responseRoot = contentRootFor(responseElement);
328→        const responseText = normalizeWhitespace(
329→          (responseRoot as HTMLElement).innerText,
330→        );
331→
332→        if (!responseText) {
333→          return;
334→        }
335→
336→        const responseBlocks = Array.from(responseRoot.childNodes).flatMap(
337→          (childNode) => {
338→            if (childNode.nodeType === Node.TEXT_NODE) {
339→              const text = normalizeWhitespace(childNode.textContent ?? "");
340→              return text ? [{ type: "paragraph" as const, text }] : [];
341→            }
342→
343→            if (childNode.nodeType !== Node.ELEMENT_NODE) {
344→              return [];
345→            }
346→
347→            return elementToBlocks(childNode as Element);
348→          },
349→        );
350→        const finalBlocks =
351→          responseBlocks.length > 0
352→            ? responseBlocks
353→            : [{ type: "paragraph" as const, text: responseText }];
354→
355→        messages.push({
356→          id: `${turnId}-assistant`,
357→          role: "assistant" as const,
358→          rawText: responseText,
359→          rawHtml: (responseRoot as HTMLElement).innerHTML,
360→          blocks: finalBlocks,
361→          parser: {
362→            source:
363→              responseBlocks.length > 0
364→                ? "gemini-response-container"
365→                : "gemini-response-fallback",
366→            blockCount: finalBlocks.length,
367→            usedFallback: responseBlocks.length === 0,
368→            strategy:
369→              responseBlocks.length > 0
370→                ? ("deterministic" as const)
371→                : ("fallback" as const),
372→          },
373→        });
374→      });
375→
376→      if (messages.length === 0) {
377→        return {
378→          title: pickGeminiTitle(),
379→          messages: [],
380→          warnings: [
381→            "Gemini share turn containers found but no extractable messages.",
382→          ],
383→        };
384→      }
385→
386→      return {
387→        title: pickGeminiTitle(),
388→        messages,
389→        warnings: [
390→          `Parsed ${turnElements.length} Gemini share turn(s) from provider-specific containers.`,
391→        ],
392→      };
393→    });
394→
395→    options?.onStage?.("normalize");
396→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
397→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
398→
399→    const previewText = normalizedPayload.messages
400→      .slice(0, 3)
401→      .flatMap((message) =>
402→        message.blocks
403→          .map((block) => {
404→            switch (block.type) {
405→              case "paragraph":
406→              case "quote":
407→              case "code":
408→                return block.text;
409→              case "heading":
410→                return block.text;
411→              case "list":
412→                return block.items.join(" ");
413→              case "table":
414→                return [...block.headers, ...block.rows.flat()].join(" ");
415→              default:
416→                return undefined;
417→            }
418→          })
419→          .filter(Boolean),
420→      )
421→      .join(" ")
422→      .slice(0, MAX_PREVIEW_TEXT_LENGTH);
423→
424→    if (looksLikeGoogleConsentContent(normalizedPayload.title, previewText)) {
425→      throw new Error(
426→        "Google returned a cookie consent screen instead of the gemini conversation.",
427→      );
428→    }
429→
430→    if (normalizedPayload.messages.length === 0) {
431→      throw new Error(
432→        "No importable messages were detected on this gemini page.",
433→      );
434→    }
435→
436→    options?.onStage?.("structure");
437→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
438→    const warnings = [...normalizedPayload.warnings, ...structured.warnings];
439→
440→    if (!looksLikeSharedConversationUrl(url)) {
441→      warnings.push(
442→        "The URL does not look like a typical public share page path, so extraction may be noisier than usual.",
443→      );
444→    }
445→
446→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
447→      ...normalizedPayload,
448→      messages: structured.messages,
449→      warnings,
450→      structuring: structured.structuring,
451→    });
452→    const rawHtml = await page.content();
453→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
454→    const fetchedAt = new Date().toISOString();
455→
456→    const conversation = conversationSchema.parse({
457→      id: crypto.randomUUID(),
458→      title: finalPayload.title,
459→      source: {
460→        url,
461→        platform: "gemini",
462→      },
463→      messages: finalPayload.messages,
464→    });
465→
466→    return {
467→      conversation,
468→      warnings: finalPayload.warnings,
469→      snapshot: {
470→        finalUrl: page.url(),
471→        fetchedAt,
472→        pageTitle: finalPayload.title,
473→        rawHtml,
474→        normalizedPayload: finalPayload,
475→        fetchMetadata: {
476→          articleCount: normalizedPayload.messages.length,
477→          messageCount: conversation.messages.length,
478→          rawHtmlBytes,
479→        },
480→      },
481→    };
482→  } finally {
483→    await releaseContext(context);
484→  }
485→}
