 1→import type {
 2→  Conversation,
 3→  ImportStage,
 4→  NormalizedSnapshotPayload,
 5→} from "@chat-exporter/shared";
 6→
 7→/** Callback for reporting import stage progress. */
 8→export type StageCallback = (
 9→  stage: Extract<ImportStage, "fetch" | "extract" | "normalize" | "structure">,
10→) => void;
11→
12→/** Standardized result returned by every platform parser. */
13→export type PlatformParserResult = {
14→  conversation: Conversation;
15→  warnings: string[];
16→  snapshot: {
17→    finalUrl: string;
18→    fetchedAt: string;
19→    pageTitle: string;
20→    rawHtml: string;
21→    normalizedPayload: NormalizedSnapshotPayload;
22→    fetchMetadata: {
23→      articleCount: number;
24→      messageCount: number;
25→      rawHtmlBytes: number;
26→    };
27→  };
28→};
29→
30→/** Signature that every platform-specific parser function must implement. */
31→export type PlatformParser = (
32→  url: string,
33→  options?: { onStage?: StageCallback },
34→) => Promise<PlatformParserResult>;
